    /**@ch 開始Spin，處理相關設置 */
    StartSpin()
    {
        this.m_time = 0;
        this.StopTime = 0;
        this.m_isStop = false;
        this.m_isClickStopBtn = false;
        this.m_isPlayStopSound.fill( false );
        this.m_isPlayStopEffect.fill( false );

        for ( let i = 0; i < Game_Define.COL; ++i )
        {
            this.m_reelStopTime[ i ] = this.m_reelPreTime[ i ] = null;
        }

        // 預算各列轉一圈時間（m_spinTime 與 GetTargetSymbolCount 於 spin 期間不變）
        for ( let i = 0; i < Game_Define.COL; ++i )
        {
            this.m_cachedSpinTimes[ i ] = this.CalSpinTime( i, false );
        }

        // 重置所有符號切換狀態（但保留鎖定狀態）
        for ( let col = 0; col < this.m_isChangeToFinalSymbol.length; ++col )
        {
            // 只重置未鎖定的轉輪
            if ( !this.m_lockColumn[ col ] )
            {
                this.m_isChangeToFinalSymbol[ col ] = false;
            }
        }

        // 清空並重新初始化有效的列索引（只對中輪帶）
        this.m_isNotChangeSymbolThisRound = {};
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            this.m_isNotChangeSymbolThisRound[ col ] = true;
        }

        // 初始化上下輪帶狀態
        this.m_upDownReelChangeState = {};
        for ( let plate = 0; plate < this.m_layoutConfig.plateCount; ++plate )
        {
            for ( let col = 0; col < Game_Define.COL; ++col )
            {
                const nodeName = this.GetPlateNamePrefix( plate ) + col.toString();
                if ( plate !== this.MiddlePlateIndex ) // 只處理上下輪帶
                {
                    this.m_upDownReelChangeState[ nodeName ] = true;
                }
            }
        }
    }

    /**
     * @ch 停輪相關表演
     * @param isFast 是否快速停輪
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     */
    async ShowStopSymbolEffect( isFast: boolean, col: number )
    {
        if ( this.m_isPlayStopEffect[ col ] )
        {
            return;
        }

        this.m_isPlayStopEffect[ col ] = true;

        // NearWin / Scatter 停輪偵測
        this.m_nearWinDetector?.OnColumnStopped(col, this.m_plateInfo as any);
    }

    /**
     * @ch 盤面對帳不一致時的回呼（注入式）。
     * 預設 null → CheckPlateInfo 只 error() log（不上報、不踢玩家）。
     * GameView 可經 SetPlateDesyncHandler 接上 ConnectionManager.SendErrorLog / 踢玩家，
     * 以保持 SlotReels 不直接依賴 framework 的連線/訊息框模組（解耦）。
     */
    private m_onPlateDesync: PlateDesyncHandler | null = null;

    /**
     * @ch 設定盤面對帳不一致的處理回呼（傳 null 取消）
     * @param handler 收到不一致 errorObj 時呼叫；null = 只 log
     */
    SetPlateDesyncHandler( handler: PlateDesyncHandler | null )
    {
        this.m_onPlateDesync = handler;
    }

    /**
     * @ch 檢查盤面是否正確：逐格比對 server 盤面與畫面顯示 symbol。
     * 不一致時每格 error() log；若已設定 desync handler 則額外回呼（由 GameView 決定上報/踢玩家）。
     */
    CheckPlateInfo()
    {
        if (!this.m_plateInfo || this.m_plateInfo.length === 0) {
            return;
        }

        let errorObj: PlateDesyncError = { errors: [] };
        let hasError = false;

        let serverSymbol = 0;
        let showSymbol = 0;
        for ( let col = 0; col < this.m_plateInfo.length; col++ )
        {
            for ( let row = 0; row < this.m_plateInfo[ col ].Col.length; row++ )
            {
                serverSymbol = this.m_plateInfo[ col ].Col[ row ].Symbol;
                showSymbol = this.m_allColumns[ this.MiddlePlateIndex ][ col ].Symbols[ row ];
                if ( serverSymbol !== showSymbol )
                {
                    errorObj.errors.push( { col: col, row: row } );
                    error( `盤面錯誤: col=${col}, row=${row} ServerSymbol = ${serverSymbol} 畫面Symbol = ${showSymbol}` );
                    hasError = true;
                }
            }
        }

        if ( !hasError )
        {
            return;
        }

        // @ch 預設只 log（上方迴圈已 error()）；接了 handler 才上報/踢玩家，避免 SlotReels 直接耦合 framework
        this.m_onPlateDesync?.( errorObj );
    }

