    };
    static LOGIN_RESULT_TYPE = {
        LOGIN_SUCCESS: 0, //登入成功
        LOGIN_FAIL: 1, // 登入失敗
        API_VERIFY_FAIL: 2001,   // TOKEN驗證失敗
        API_LOGIN_REPEAT_FAIL: 2002,    // 重複登入
    };
    static HEART_BEAT_STATE = {
        NOTIFY: 97, //SERVER 通知訊息
        MAINTAIN: 98, //SERVER 維護中
        CLOSE: 99, //SERVER 關閉
    };
    static StringKey = {
        MC_FEATURES_LEFT: "MC_FEATURES_LEFT",
        MC_FEATURES_RIGHT: "MC_FEATURES_RIGHT",
        FREE_GAME_NAME_STRING: "FREE_GAME_NAME_STRING",
    };

    static ShowDisplayValue: ( value: number ) => number = null;

    /**@ch 特色遊玩押注 */
    static FeatureBetValue = 10;

    static OnExit()
    {
        this.ShowDisplayValue = null;
    }
}

