/**
 * @ch 播放主遊戲背景音樂
 */
PlayMainGameBgm()
{
    if (this.m_bgmId === -1)
    {
        this.m_bgmId = AudioManager.Play( AudioManager.AudioClips.MG_Bgm, true );
    }
}

/**
 * @ch 停止主遊戲背景音樂
 */
StopMainGameBgm()
{
    if (this.m_bgmId !== -1)
    {
        AudioManager.Stop(this.m_bgmId);
        this.m_bgmId = -1;
    }
}

/**
 * @ch 暫停主遊戲背景音樂
 */
PauseMainGameBgm()
{
    if (this.m_bgmId !== -1)
    {
        AudioManager.Pause(this.m_bgmId);
    }
}

