import { _decorator, AudioClip, JsonAsset } from 'cc';
import { soundAudioManager } from 'db://astarte-framework/Managers';
const { ccclass, property } = _decorator;

/**@en Overflow strategy when concurrent limit is exceeded @ch 並發限制超過時的處理策略 */
export enum ConcurrentOverflowStrategy {
    /**@en Ignore new audio requests @ch 忽略新的音效請求 */
    IGNORE = 'ignore',
    /**@en Stop the oldest playing audio and play new one @ch 停止最舊的音效並播放新的 */
    REPLACE_OLDEST = 'replace-oldest'
}

@ccclass('AudioManager')
export class AudioManager {
    /**@en Audio file root @ch 音效檔案根目錄 */
    static AudioFileRoot = "Sound/";

    /**@en Concurrent playing instances tracking @ch 並發播放實例追蹤 */
    private static m_playingInstances: Map<string, Set<number>> = new Map();

    /**@en Concurrent limit configuration for each audio @ch 每個音效的並發限制配置 */
    private static m_concurrentLimits: Map<string, number> = new Map();

    /**@en Default concurrent limit @ch 預設並發限制 */
    private static m_defaultConcurrentLimit: number = -1; // -1 means no limit

    /**@en Overflow strategy @ch 超限處理策略 */
    private static m_overflowStrategy: ConcurrentOverflowStrategy = ConcurrentOverflowStrategy.IGNORE;

    /**@en Audio instance metadata tracking @ch 音效實例元數據追蹤 */
    private static m_instanceMetadata: Map<number, { audioKey: string, startTime: number }> = new Map();

    /**@en Audio clips @ch 音效 */
    static AudioClips = {
        // Key: { FileName: 音效檔名, Clip: AudioClip，初始為null，需要載入 }
        MG_Bgm: { FileName: "main_bgm", Clip: null },
        FG_Bgm: { FileName: "fg_bgm", Clip: null },
    };

    /**
     * 取得音效片段
     * @description 根據鍵名從 AudioClips 中取得對應的音效片段
     * @param key 音效鍵名，必須是 AudioClips 中存在的鍵
     * @returns 返回對應的 AudioClip 物件，如果找不到則返回 null
     * @example
     * ```typescript
     * const clip = AudioManager.GetAudioClip("G97_Main_Bgm");
     * if (clip) {
     *     // 使用音效片段
     * }
     * ```
     */
    static GetAudioClip(key: string): AudioClip {
        if (this.AudioClips.hasOwnProperty(key))
        {
            return this.AudioClips[key].Clip;
        }
        return null;
    }

    /**
     * 清除所有音效片段
     * @description 將所有 AudioClips 中的 Clip 設為 null，釋放記憶體
     * @example
     * ```typescript
     * AudioManager.ClearAudioClip(); // 清除所有音效片段
     * ```
     */
    static ClearAudioClip()
    {
        for (const key in this.AudioClips)
        {
            this.AudioClips[key].Clip = null;
        }
    }

    /**
     * 取得靜音狀態
     * @description 檢查音效管理器是否處於靜音狀態
     * @returns 返回 true 表示靜音，false 表示非靜音
     * @example
     * ```typescript
     * if (AudioManager.IsMute) {
     *     console.log("目前為靜音狀態");
     * }
     * ```
     */
    static get IsMute(): boolean {
        return soundAudioManager.IsMute;
    }

    /**
     * 播放音效
     * @description 播放音效，支援字串鍵名、AudioClip 物件或包含檔名和片段的物件，並支援並發限制
     * @param input 音效來源，可以是字串鍵名、AudioClip 物件或音效資料物件
     * @param loop 是否循環播放，預設為 false
     * @param cb 播放完成後的回調函式
     * @param volume 播放音量，範圍 0-1，預設使用系統音量
     * @returns 返回音效的唯一 ID，如果因並發限制而無法播放則返回 -1
     * @example
     * ```typescript
     * // 透過字串鍵名播放音效
     * const id = AudioManager.Play("background_music", true);
     *
     * // 播放音效並設定回調
     * AudioManager.Play("win_count_end", false, () => {
     *     console.log("音效播放完成");
     * });
     *
     * // 使用 AudioManager.AudioClips 中的音效片段
     * AudioManager.Play(AudioManager.AudioClips.Spin);
     *
     * // 檢查是否成功播放
     * const playId = AudioManager.Play("some_audio");
     * if (playId === -1) {
     *     console.log("音效因並發限制而無法播放");
     * }
     * ```
     */
    static Play(input: string, loop?: boolean, cb?: () => void, volume?: number): number;
    static Play(input: AudioClip, loop?: boolean, cb?: () => void, volume?: number): number;
    static Play(input: { FileName: string, Clip: AudioClip }, loop?: boolean, cb?: () => void, volume?: number): number;
    static Play( input: string | AudioClip | { FileName: string, Clip: AudioClip }, loop?: boolean, cb?: () => void, volume?: number ): number {
        let audio: AudioClip;
        let audioKey: string;

        if (typeof input === 'string') {
            audio = this.GetAudioClip(input);
            audioKey = input;
        } else if (typeof input === 'object' && 'Clip' in input) {
            audio = input.Clip;
            audioKey = input.FileName;
        } else {
            audio = input;
            audioKey = audio?.name || 'unknown';
        }

        // 檢查並發限制
        const canPlay = this.CheckConcurrentLimit(audioKey);
        if (!canPlay) {
            console.warn(`音效 "${audioKey}" 因並發限制而無法播放`);
            return -1;
        }

        // 包裝回調函數以實現自動清理
        const wrappedCallback = () => {
            if (cb) cb();
            // 清理追蹤記錄
            this.RemovePlayingInstance(audioKey, audioId);
        };

        // 播放音效
        const audioId = soundAudioManager.Play(audio, loop, wrappedCallback, volume);

        if (audioId !== -1) {
            // 記錄播放實例
            this.AddPlayingInstance(audioKey, audioId);
        }

        return audioId;
    }  

    /**
     * 播放背景音效
     * @description 播放背景音樂或長時間循環音效，支援字串鍵名、AudioClip 物件或包含檔名和片段的物件，並支援並發限制
     * @param input 音效來源，可以是字串鍵名、AudioClip 物件或音效資料物件
     * @param loop 是否循環播放，背景音樂通常設為 true
     * @param cb 播放完成後的回調函式
     * @param volume 播放音量，範圍 0-1，預設使用系統音量
     * @returns 返回音效的唯一 ID，如果因並發限制而無法播放則返回 -1
     * @example
     * ```typescript
     * // 透過字串鍵名播放背景音樂
     * const bgmId = AudioManager.PlayBackGround("main_bgm", true);
     *
     * // 播放免費遊戲背景音樂並設定音量
     * const fgBgmId = AudioManager.PlayBackGround("freegame_bgm", true, null, 0.5);
     *
     * // 使用 AudioClip 物件播放
     * AudioManager.PlayBackGround(bgmAudioClip, true);
     *
     * // 使用包含檔名的物件
     * AudioManager.PlayBackGround({ FileName: "bgm", Clip: audioClip }, true);
     * ```
     */
    static PlayBackGround(input: string, loop?: boolean, cb?: () => void, volume?: number): number;
    static PlayBackGround(input: AudioClip, loop?: boolean, cb?: () => void, volume?: number): number;
    static PlayBackGround(input: { FileName: string, Clip: AudioClip }, loop?: boolean, cb?: () => void, volume?: number): number;
    static PlayBackGround( input: string | AudioClip | { FileName: string, Clip: AudioClip }, loop?: boolean, cb?: () => void, volume?: number ): number {
        let audio: AudioClip;
        let audioKey: string;

        if (typeof input === 'string') {
            audio = this.GetAudioClip(input);
            audioKey = input + '_bg';
        } else if (typeof input === 'object' && 'Clip' in input) {
            audio = input.Clip;
            audioKey = input.FileName + '_bg';
        } else {
            audio = input;
            audioKey = (audio?.name || 'unknown') + '_bg';
        }

        // 檢查並發限制
        const canPlay = this.CheckConcurrentLimit(audioKey);
        if (!canPlay) {
            console.warn(`背景音效 "${audioKey}" 因並發限制而無法播放`);
            return -1;
        }

        // 包裝回調函數以實現自動清理
        const wrappedCallback = () => {
            if (cb) cb();
            // 清理追蹤記錄
            this.RemovePlayingInstance(audioKey, audioId);
        };

        // 播放背景音效
        const audioId = soundAudioManager.PlayBackGround(audio, loop, wrappedCallback, volume);

        if (audioId !== -1) {
            // 記錄播放實例
            this.AddPlayingInstance(audioKey, audioId);
        }

        return audioId;
    }

    /**
     * 停止音效播放
     * @description 根據音效 ID 停止指定的音效播放，並自動清理追蹤記錄
     * @param id 音效的唯一 ID，由 Play 或 PlayBackGround 方法返回
     * @param audioName 音效名稱，用於額外確認，避免停錯音效（可選）
     * @example
     * ```typescript
     * const id = AudioManager.Play("G97_Reelspin");
     * // 停止播放
     * AudioManager.Stop(id);
     *
     * // 帶名稱確認的停止
     * AudioManager.Stop(id, "G97_Reelspin");
     * ```
     */
    static Stop( id: number, audioName?: string ): void {
        soundAudioManager.Stop(id, audioName);

        // 清理追蹤記錄
        const metadata = this.m_instanceMetadata.get(id);
        if (metadata) {
            this.RemovePlayingInstance(metadata.audioKey, id);
        }
    }

    /**
     * 恢復音效播放
     * @description 恢復之前暫停的音效播放
     * @param id 音效的唯一 ID
     * @example
     * ```typescript
     * const id = AudioManager.Play("G97_Main_Bgm", true);
     * AudioManager.Pause(id);  // 暫停
     * AudioManager.Resume(id); // 恢復播放
     * ```
     */
    static Resume( id: number ): void {
        soundAudioManager.Resume(id);
    }

    /**
     * 暫停音效播放
     * @description 暫停指定音效的播放，可以使用 Resume 恢復
     * @param id 音效的唯一 ID
     * @example
     * ```typescript
     * const id = AudioManager.Play("G97_Main_Bgm", true);
     * AudioManager.Pause(id); // 暫停播放
     * ```
     */
    static Pause( id: number ): void {
        soundAudioManager.Pause(id);
    }

    /**
     * 設定音效音量
     * @description 動態調整指定音效的播放音量
     * @param id 音效的唯一 ID
     * @param vol 音量值，範圍 0-1，0 為靜音，1 為最大音量
     * @example
     * ```typescript
     * const id = AudioManager.Play("G97_Main_Bgm", true);
     * AudioManager.SetVolume(id, 0.5); // 設定為 50% 音量
     * ```
     */
    static SetVolume( id: number, vol: number ): void {
        soundAudioManager.SetVolume(id, vol);
    }

    /**
     * 取得音效音量
     * @description 獲取指定音效的當前音量
     * @param id 音效的唯一 ID
     * @returns 返回音量值，範圍 0-1
     * @example
     * ```typescript
     * const id = AudioManager.Play("G97_Main_Bgm", true);
     * const volume = AudioManager.GetVolume(id);
     * console.log(`當前音量: ${volume}`);
     * ```
     */
    static GetVolume( id: number ): number {
        return soundAudioManager.GetVolume(id);
    }

    /**
     * 取得音效播放狀態
     * @description 獲取指定音效的播放狀態
     * @param id 音效的唯一 ID
     * @returns 返回音效狀態代碼 (0: 停止, 1: 播放中, 2: 暫停)
     * @example
     * ```typescript
     * const id = AudioManager.Play("G97_Main_Bgm", true);
     * const state = AudioManager.GetAudioStateById(id);
     * if (state === 1) {
     *     console.log("音效播放中");
     * }
     * ```
     */
    static GetAudioStateById( id: number ): number {
        return soundAudioManager.GetAudioStateById(id);
    }

    /**
     * 設定音效淡入效果
     * @description 讓指定音效以淡入方式播放，音量漸漸增加
     * @param id 音效的唯一 ID
     * @param fadeInTime 淡入時間（秒），預設值由系統決定
     * @param maxVolume 淡入後的最大音量，範圍 0-1，預設值由系統決定
     * @example
     * ```typescript
     * const id = AudioManager.Play("G97_Main_Bgm", true);
     * AudioManager.SetMusicFadeIn(id, 3.0, 0.8); // 3秒淡入到80%音量
     * ```
     */
    static SetMusicFadeIn( id: number, fadeInTime?: number, maxVolume?: number ): void {
        soundAudioManager.SetMusicFadeIn(id, fadeInTime, maxVolume);
    }

    /**
     * 設定音效淡出效果
     * @description 讓指定音效以淡出方式停止播放，音量漸漸減少至靜音
     * @param id 音效的唯一 ID
     * @param fadeOutTime 淡出時間（秒），預設值由系統決定
     * @example
     * ```typescript
     * const id = AudioManager.Play("G97_Main_Bgm", true);
     * AudioManager.SetMusicFadeOut(id, 2.0); // 2秒淡出
     * ```
     */
    static SetMusicFadeOut( id: number, fadeOutTime?: number ): void {
        soundAudioManager.SetMusicFadeOut(id, fadeOutTime);
    }

    /**
     * 設定音效配置檔案
     * @description 載入音效混音器配置檔案，用於設定音效的混音參數
     * @param audioMixerFile 音效混音器配置檔案 (JsonAsset)
     * @warning 如果已設定過其他配置檔案，建議先呼叫 ClearSetting() 清除舊設定
     * @example
     * ```typescript
     * // 載入配置檔案
     * AudioManager.SetSettingJson(audioMixerAsset);
     * ```
     */
    static SetSettingJson( audioMixerFile: JsonAsset ): void {
        soundAudioManager.SetSettingJson(audioMixerFile);
    }

    /**
     * 清除音效配置檔案
     * @description 清除當前的音效配置檔案，釋放相關資源
     * @usage 在換場景或設定新的音效配置檔案前使用
     * @example
     * ```typescript
     * // 場景切換時清除配置
     * AudioManager.ClearSetting();
     * ```
     */
    static ClearSetting(): void {
        soundAudioManager.ClearSetting();
    }

    /**
     * 新增音效片段清單
     * @description 將音效片段陣列新增到音效管理器中
     * @param audioList 音效片段陣列
     * @note 即使不呼叫此方法也可以使用 Play 播放音效，但呼叫後才會在 AudioTool 清單中顯示
     * @example
     * ```typescript
     * const audioClips = [clip1, clip2, clip3];
     * AudioManager.AddAudioClips(audioClips);
     * ```
     */
    static AddAudioClips( audioList: AudioClip[] ): void {
        soundAudioManager.AddAudioClips(audioList);
    }

    // =================================================================
    // 並發限制管理方法 (Concurrent Limit Management Methods)
    // =================================================================

    /**
     * 設定音效並發限制
     * @description 為指定音效設定同時間可播放的最大數量
     * @param audioKey 音效鍵名，對應 AudioClips 中的鍵名
     * @param maxCount 最大並發數量，設為 -1 表示無限制
     * @example
     * ```typescript
     * // 設定技能爆炸音效同時間最多只能播放 3 個
     * AudioManager.SetConcurrentLimit("skill_explosion", 3);
     *
     * // 設定按鈕音效同時間最多只能播放 1 個
     * AudioManager.SetConcurrentLimit("button_click", 1);
     *
     * // 移除限制
     * AudioManager.SetConcurrentLimit("background_music", -1);
     * ```
     */
    static SetConcurrentLimit(audioKey: string, maxCount: number): void {
        if (maxCount <= 0 && maxCount !== -1) {
            console.warn(`無效的並發限制數量: ${maxCount}，應該大於 0 或設為 -1`);
            return;
        }

        if (maxCount === -1) {
            this.m_concurrentLimits.delete(audioKey);
        } else {
            this.m_concurrentLimits.set(audioKey, maxCount);
        }
    }

    /**
     * 設定預設並發限制
     * @description 設定所有音效的預設並發限制，對於沒有特別設定的音效生效
     * @param maxCount 預設最大並發數量，設為 -1 表示無限制
     * @example
     * ```typescript
     * // 設定所有音效預設最多同時播放 5 個
     * AudioManager.SetDefaultConcurrentLimit(5);
     *
     * // 移除預設限制
     * AudioManager.SetDefaultConcurrentLimit(-1);
     * ```
     */
    static SetDefaultConcurrentLimit(maxCount: number): void {
        if (maxCount <= 0 && maxCount !== -1) {
            console.warn(`無效的預設並發限制數量: ${maxCount}，應該大於 0 或設為 -1`);
            return;
        }
        this.m_defaultConcurrentLimit = maxCount;
    }

    /**
     * 設定超限處理策略
     * @description 設定當並發播放數量超過限制時的處理方式
     * @param strategy 處理策略：'ignore' 忽略新請求；'replace-oldest' 停止最舊的音效
     * @example
     * ```typescript
     * // 設定為忽略新請求
     * AudioManager.SetOverflowStrategy(ConcurrentOverflowStrategy.IGNORE);
     *
     * // 設定為停止最舊的音效
     * AudioManager.SetOverflowStrategy(ConcurrentOverflowStrategy.REPLACE_OLDEST);
     * ```
     */
    static SetOverflowStrategy(strategy: ConcurrentOverflowStrategy): void {
        this.m_overflowStrategy = strategy;
    }

    /**
     * 查詢當前音效播放數量
     * @description 取得指定音效當前正在播放的實例數量
     * @param audioKey 音效鍵名
     * @returns 當前播放數量
     * @example
     * ```typescript
     * const currentCount = AudioManager.GetCurrentPlayingCount("skill_explosion");
     * console.log(`技能爆炸音效當前播放數量: ${currentCount}`);
     * ```
     */
    static GetCurrentPlayingCount(audioKey: string): number {
        const instances = this.m_playingInstances.get(audioKey);
        return instances ? instances.size : 0;
    }

    /**
     * 查詢音效並發限制
     * @description 取得指定音效的並發限制設定
     * @param audioKey 音效鍵名
     * @returns 並發限制數量，-1 表示無限制
     * @example
     * ```typescript
     * const limit = AudioManager.GetConcurrentLimit("skill_explosion");
     * if (limit === -1) {
     *     console.log("技能爆炸音效無並發限制");
     * } else {
     *     console.log(`技能爆炸音效並發限制: ${limit}`);
     * }
     * ```
     */
    static GetConcurrentLimit(audioKey: string): number {
        return this.m_concurrentLimits.get(audioKey) || this.m_defaultConcurrentLimit;
    }

    /**
     * 停止指定音效的所有實例
     * @description 停止指定音效的所有正在播放的實例
     * @param audioKey 音效鍵名
     * @returns 停止的音效數量
     * @example
     * ```typescript
     * const stoppedCount = AudioManager.StopAllInstances("skill_explosion");
     * console.log(`已停止 ${stoppedCount} 個技能爆炸音效`);
     * ```
     */
    static StopAllInstances(audioKey: string): number {
        const instances = this.m_playingInstances.get(audioKey);
        if (!instances || instances.size === 0) {
            return 0;
        }

        let stoppedCount = 0;
        for (const audioId of instances) {
            soundAudioManager.Stop(audioId);
            this.m_instanceMetadata.delete(audioId);
            stoppedCount++;
        }

        instances.clear();
        return stoppedCount;
    }

    /**
     * 清除所有並發限制設定
     * @description 清除所有音效的並發限制設定和播放記錄
     * @example
     * ```typescript
     * AudioManager.ClearAllConcurrentLimits();
     * ```
     */
    static ClearAllConcurrentLimits(): void {
        this.m_concurrentLimits.clear();
        this.m_playingInstances.clear();
        this.m_instanceMetadata.clear();
        this.m_defaultConcurrentLimit = -1;
        this.m_overflowStrategy = ConcurrentOverflowStrategy.IGNORE;
    }

    // =================================================================
    // 內部方法 (Private Methods)
    // =================================================================

    /**
     * 檢查並發限制
     * @description 檢查指定音效是否可以播放，如果超過限制則根據策略處理
     * @param audioKey 音效鍵名
     * @returns 是否可以播放
     */
    private static CheckConcurrentLimit(audioKey: string): boolean {
        const limit = this.GetConcurrentLimit(audioKey);
        if (limit === -1) {
            return true; // 無限制
        }

        const currentCount = this.GetCurrentPlayingCount(audioKey);
        if (currentCount < limit) {
            return true; // 未超過限制
        }

        // 超過限制，根據策略處理
        if (this.m_overflowStrategy === ConcurrentOverflowStrategy.REPLACE_OLDEST) {
            this.StopOldestInstance(audioKey);
            return true;
        }

        return false; // 忽略新請求
    }

    /**
     * 停止最舊的音效實例
     * @description 停止指定音效的最舊播放實例
     * @param audioKey 音效鍵名
     */
    private static StopOldestInstance(audioKey: string): void {
        const instances = this.m_playingInstances.get(audioKey);
        if (!instances || instances.size === 0) {
            return;
        }

        let oldestId = -1;
        let oldestTime = Number.MAX_VALUE;

        // 找出最舊的實例
        for (const audioId of instances) {
            const metadata = this.m_instanceMetadata.get(audioId);
            if (metadata && metadata.startTime < oldestTime) {
                oldestTime = metadata.startTime;
                oldestId = audioId;
            }
        }

        if (oldestId !== -1) {
            soundAudioManager.Stop(oldestId);
            this.RemovePlayingInstance(audioKey, oldestId);
        }
    }

    /**
     * 添加播放實例
     * @description 將新的音效實例添加到追蹤列表
     * @param audioKey 音效鍵名
     * @param audioId 音效 ID
     */
    private static AddPlayingInstance(audioKey: string, audioId: number): void {
        if (!this.m_playingInstances.has(audioKey)) {
            this.m_playingInstances.set(audioKey, new Set());
        }
        this.m_playingInstances.get(audioKey)!.add(audioId);

        // 記錄元數據
        this.m_instanceMetadata.set(audioId, {
            audioKey: audioKey,
            startTime: Date.now()
        });
    }

    /**
     * 移除播放實例
     * @description 從追蹤列表中移除指定的音效實例
     * @param audioKey 音效鍵名
     * @param audioId 音效 ID
     */
    private static RemovePlayingInstance(audioKey: string, audioId: number): void {
        const instances = this.m_playingInstances.get(audioKey);
        if (instances) {
            instances.delete(audioId);
            if (instances.size === 0) {
                this.m_playingInstances.delete(audioKey);
            }
        }

        this.m_instanceMetadata.delete(audioId);
    }
}

