            window.onerror = (errorMessage, scriptURI, lineNumber, columnNumber, errorObj) => {
                let id = "-1";
                let apiId = 0;
                if (Define.APP) {
                    id = Define.APP.GetAID();
                    apiId = Number(Define.APP.GetApiID());
                }
                let params = ConnectionManager.FormErrorParams(
                    id,
