    start() {
        this.LoadSymbol();
        // this.LoadJp();

        if (!tools.CheckSwitchOff(SwitchOffKeyDefine.NoQuickSpin)) {
            input.on(Input.EventType.KEY_DOWN, (event: EventKeyboard) => {
                switch (event.keyCode) {
                    case KeyCode.SPACE:
                        if (
                            msgBoxManager.IsShow()
