    OnRecvSpinAck( ack, isUnshow = false )
    {
        error( "SpinAck before :", ack );

        let info = RecoverSpinAck.getInstance().RecoverSpinAck( ack );
        console.error( "SpinAck :", info );
        this.SpinAck = info;        

        if ( this.SpinAck.RoundQueue.length > 1 )
        {
            if ( !isUnshow || this.CurPlateIndex === 0 )
            {
                // 檢查第一輪是否為FreeGame 或 RespinGame
                const firstRound = this.SpinAck.RoundQueue[0];
                if (firstRound.FreePlateSymbol.length > 0 && firstRound.NextFeverGameType > 0)
