            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
        }

        // 設定當局盤面資訊
        this.SetNowRoundInfo( this.SpinAck.RoundQueue[ this.CurPlateIndex ] );

        // ClickStopBtn（快停）已移至 SpinState.OnEnter 的 SetNowRoundInfo 之後，
        // 確保 SetReelTimes 先執行再計算快停時間
        if ( this.IsHardStop )
