        //     }
        // }

        // const plateSymbol = (this.IsRespinGame || this.IsFreeGame) ? this.RoundInfo.FreePlateSymbol : this.RoundInfo.MainPlateSymbol;
        this.m_slotReels?.SetPlateInfo( RecoverSpinAck.getInstance().ConvertPlate( this.RoundInfo.MainPlateSymbol ) );
