    /**
     * @ch 更新停輪相關時間
     * @en Update stopTime, reelStopTime, reelPreTime and ClickStopBtn
     */
    ClickStopBtn()
    {
        if ( this.StopTime === 0 )
        {
            return;
        }

        this.m_isClickStopBtn = true;

        for ( let i = 0; i < Game_Define.COL; ++i )
        {
            let spinTime = this.m_cachedSpinTimes[ i ];
            let timesOfSpin = Math.ceil( this.m_time / spinTime ); // NOTE: 不加一的話有可能會偷換圖
            timesOfSpin = timesOfSpin > 0 ? timesOfSpin : 1;
            let reelPreTime = ( timesOfSpin - 1 ) * spinTime; // 差一圈就要停時的時間
            let reelStopTime = this.ToolsStrip( reelPreTime + spinTime );
            if ( this.m_reelStopTime[ i ] > reelStopTime )
            {
                this.m_reelStopTime[ i ] = reelStopTime;
                this.m_reelPreTime[ i ] = reelPreTime;
            }
        }

        // let stopTime = reelStopTime
        //     + this.m_spinDelayTime
        //     + this.m_spinBufferTime01
        //     + this.m_spinBufferTime02;

        // 轉輪節奏模組：三幣瑞龍
        // let stopTime = tempoSetting.TempoSetting.TripleCoinTreasure.SPEED_UP_STOP_TIME( 0, this.m_time );
        let stopTime = this.CalClickStopButtonFinishTime( this.m_time );

        if ( stopTime < this.m_stopTime )
        {
            this.StopTime = this.ToolsStrip( stopTime );
        }
    }

    /**
     * @ch 旋轉
     * @param dt 時間
     */
    Spin( dt )
    {
        this.m_time = this.ToolsStrip( this.m_time + dt );
        if ( this.IsStop )
        {
            return;
        }

        this.SpinAll( dt, NORMAL_COLUMNS );

        if ( this.StopTime === 0 || this.m_time <= this.StopTime )
        {
            return;
        }

        this.CheckPlateInfo();

        // 該停輪了
        this.m_isStop = true;

        if ( this.m_reelSoundId )
        {
            // soundAudioManager.Stop( this.m_reelSoundId );
            this.m_reelSoundId = null;
        }
    }

    /**
     * @ch 旋轉上、中、下所有輪帶，第二個參數為控制單輪
     * @param dt 時間
     * @param cols 列索引 (0 ~ Game_Define.COL-1)
     */
    SpinAll( dt, cols: number[] )
    {
        for ( let col = 0; col < cols.length; ++col )
        {
            const actualCol = cols[ col ];

            // 檢查轉輪是否被鎖定
            if ( this.m_lockColumn[ actualCol ] )
            {
                continue; // 跳過鎖定的轉輪
            }

            // 先假設不是NearWin
            let spinTime = this.m_cachedSpinTimes[ actualCol ];

            // 計算時間
            let curTime = this.m_time;
            let riseTime = this.m_totalRiseTime;
            let moveLength = ( ( ( curTime - riseTime ) % spinTime ) / spinTime ) * this.GetTotalLength( actualCol );

            // 上中下總共三條
            for ( let plate = 0; plate < this.m_layoutConfig.plateCount; ++plate )
            {
                this.Spin_RealSpinMultiple( actualCol, this.m_allColumns[ plate ][ actualCol ], plate, moveLength );
            }
        }
    }

    /**
     * @ch 根據時間，做出對應表演，座標與一般直角座標系相同
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param target 列符號
     * @param upMiddleLow 上中下輪帶
     * @param moveLength 移動長度
     */
    Spin_RealSpinMultiple( col: number, target: ColumnSymbol, upMiddleLow: number, moveLength: number )
    {
        const curTime = this.m_time;
        const reelStopTime = this.m_reelStopTime[ col ];
        // let reelPreTime = this.m_reelPreTime[ col ];
        const riseTime = this.m_totalRiseTime;

        let x = this.m_reelXPos[ col ];
        let y = this.GetReelYPos( col, upMiddleLow );
        const directionMultiplier = this.GetDirectionMultiplier();

        // ⚠️ 預先 cache 重複算術（每幀對每列每盤共用），減少分支內重算
        // ⚠️ 當 reelStopTime===null 時 stopPlusRise/Buf1/Buf2 為 NaN，此為設計選擇 —
        //    所有 `curTime < NaN` 為 false，與下方 short-circuit `reelStopTime === null ||` 等效，不影響行為
        const riseTimeCol = this.m_riseTime * col;
        const riseTimeColPlus1 = riseTimeCol + this.m_riseTime;
        const stopPlusRise = reelStopTime + riseTime;
        const stopPlusRiseBuf1 = stopPlusRise + this.m_spinBufferTime01;
        const stopPlusRiseBuf2 = stopPlusRiseBuf1 + this.m_spinBufferTime02;

        if ( curTime < riseTimeCol ) // 抬起續力表演
        {
            return;
        }
        else if ( curTime < riseTimeColPlus1 )
        {
            let moveLength = ( ( curTime - riseTimeCol ) / this.m_riseTime ) * this.m_upLength;
            this.m_tempVec3.set( x, y + moveLength, 0 );
            target.SetPosition( this.m_tempVec3 );
        }
        else if ( curTime < riseTime )
        {
            this.m_tempVec3.set( x, y + this.m_upLength, 0 );
            target.SetPosition( this.m_tempVec3 );
        }
        else if ( reelStopTime === null || curTime < stopPlusRise ) // 轉動表演
        {
            let finalMoveLength = this.CheckMoveLength( moveLength, this.GetComparePos( col, upMiddleLow ), col, target );
            this.m_tempVec3.set( x, y + directionMultiplier * finalMoveLength, 0 );
            target.SetPosition( this.m_tempVec3 );
        }
        else if ( curTime < stopPlusRiseBuf1 ) // 準備要停了
        {
            let moveLength = ( ( curTime - stopPlusRise ) / this.m_spinBufferTime01 ) * this.m_downLength;
            this.m_tempVec3.set( x, y + directionMultiplier * moveLength, 0 );
            target.SetPosition( this.m_tempVec3 );

            // 只在第一次進入停輪階段時設定最終符號
            if ( upMiddleLow === this.MiddlePlateIndex )
            {
                this.CheckChangeToFinalSymbol( col, target, true );
            }
            this.CheckPlayStopSoundAndEffect( col );
        }
        else if ( curTime < stopPlusRiseBuf2 )
        {
            let moveLength = ( ( curTime - stopPlusRiseBuf1 ) / this.m_spinBufferTime02 ) * this.m_downLength;
            const settleOffset = this.m_downLength - moveLength;
            this.m_tempVec3.set( x, y + directionMultiplier * settleOffset, 0 );
            target.SetPosition( this.m_tempVec3 );
        }
        else
        {
            // 最終停輪位置
            this.m_tempVec3.set( x, y, 0 );
            target.SetPosition( this.m_tempVec3 );

            // 只在第一次進入停輪階段時設定最終符號
            if ( upMiddleLow === this.MiddlePlateIndex )
            {
                this.CheckChangeToFinalSymbol( col, target, true );
            }

            this.CheckPlayStopSoundAndEffect( col );
            this.ShowStopSymbolEffect( this.m_isClickStopBtn, col );
        }
    }

    /**
     * @ch 確認是不是可以換Symbol了，順便拉到上面
     * @param moveLength 移動長度
     * @param comapreLength 比較長度
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param target 列符號
     * @returns 移動長度
     */
    CheckMoveLength( moveLength: number, comapreLength: number, col: number, target: ColumnSymbol )
    {
        // 如果不是中輪帶，使用類似的邏輯但獨立的狀態追蹤
        if ( !target.IsMiddleReel )
        {
            if ( moveLength < comapreLength )
            {
                return moveLength;
            }

            // 使用輪帶名稱作為狀態追蹤的鍵值
            const stateKey = target.Name;

            if (
                this.m_upDownReelChangeState[ stateKey ] !== false
                && moveLength - comapreLength < this.m_viewSize.height
            ) 
            {
                this.ChangeSymbol( col, target, this.m_isClickStopBtn );
                this.m_upDownReelChangeState[ stateKey ] = false;
            }
            else if ( moveLength - comapreLength >= this.m_viewSize.height )
            {
                // 移動超過視窗高度，重置為可換符號狀態
                this.m_upDownReelChangeState[ stateKey ] = true;
            }

            return moveLength - this.GetTotalLength( col );
        }

        // 只有中輪帶執行原本的切換邏輯
        let index = target.ReelIndex; // 這裡index就是列號 (0,1,2,3,4,5)

        if ( moveLength < comapreLength )
        {
            return moveLength;
        }

        if (
            this.m_isNotChangeSymbolThisRound[ index ]
            && moveLength - comapreLength < this.m_viewSize.height
        ) // 可以換了
        {
            this.ChangeSymbol( col, target, this.m_isClickStopBtn );
            this.m_isNotChangeSymbolThisRound[ index ] = false;
        }
        else if ( moveLength - comapreLength >= this.m_viewSize.height )
        {
            // 移動超過視窗高度，重置為可換符號狀態
            this.m_isNotChangeSymbolThisRound[ index ] = true;
        }
        // 其他情況保持現有狀態不變
        return moveLength - this.GetTotalLength( col );
    }

    /**
     * @ch 幫單個column換Symbol
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param columnSymbol 列符號
     * @param isStop 是否停輪
     */
    ChangeSymbol( col: number, columnSymbol: ColumnSymbol, isStop: boolean )
    {
        let index = columnSymbol.ReelIndex;
        let reelPreTime = this.m_reelPreTime[ col ];
        let riseTime = this.m_riseTime * this.m_viewSize.height * this.m_layoutConfig.plateCount;
        // let symbolNumber = this.GetTargetSymbolCount( col );
        let nearWin = this.m_nearWinDetector?.IsHasScatterNearWin ?? false;
        let isFakeReel = false; // 是否假輪帶

        if ( isStop )
        {
            // 停輪階段
            if ( !isNaN( index ) )
            {
                // 中間輪帶 - 使用伺服器提供的最終盤面（包含假符號）
                if ( this.m_plateInfoWithFakeSymbol && this.m_plateInfoWithFakeSymbol[ col ] && this.m_plateInfoWithFakeSymbol[ col ].Col )
                {
                    // 從 CColumn 中提取 SymbolInfo 陣列
                    const symbolInfos = this.ConvertCSymbolsToSymbolInfos( this.m_plateInfoWithFakeSymbol[ col ].Col );
                    columnSymbol.SetSymbolInfos( symbolInfos );
                }
                else
                {
                    isFakeReel = true;
                }
            }
            else
            {
                // 上下輪帶 - 使用隨機符號
                isFakeReel = true;
            }
        }
        else
        {
            let spinTime = this.CalSpinTime( col, nearWin );

            if ( !isNaN( index )
                && ( ( reelPreTime !== null && this.m_time >= reelPreTime )
                    || ( Math.abs( this.m_time - ( reelPreTime + riseTime ) ) < spinTime ) )
            )
            {
                // 中間輪帶準備停輪階段 - 使用伺服器提供的最終盤面（包含假符號）
                if ( this.m_plateInfoWithFakeSymbol && this.m_plateInfoWithFakeSymbol[ col ] && this.m_plateInfoWithFakeSymbol[ col ].Col )
                {
                    // 從 CColumn 中提取 SymbolInfo 陣列
                    const symbolInfos = this.ConvertCSymbolsToSymbolInfos( this.m_plateInfoWithFakeSymbol[ col ].Col );
                    columnSymbol.SetSymbolInfos( symbolInfos );
                }
                else
                {
                    isFakeReel = true;
                }
            }
            else
            {
                // 旋轉中或上下輪帶 - 使用隨機符號
                isFakeReel = true;
            }
        }

        if ( isFakeReel )
        {
            this.SetColumnSymbolForFakeReel( col, columnSymbol );
        }
    }

    /**
     * @ch 設定列符號資訊 假輪帶用
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param columnSymbol 列符號
     */
    SetColumnSymbolForFakeReel( col: number, columnSymbol: ColumnSymbol)
    {
        let symbols = this.CheckIsFreeGameAndGetSymbols( col );
        let symbolInfos = this.ConvertSymbolsToSymbolInfos( symbols );
        columnSymbol.SetSymbolInfos( symbolInfos );
    }

    /**
     * @ch 根據是不是FG來判斷要怎麼隨機產生symbol
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @returns 符號
     */
    CheckIsFreeGameAndGetSymbols( col: number ) : number[]
    {
        let symbols : number[] = [];
        let symbolNumber = this.GetTargetSymbolCount( col ); // 根據列獲取行數
        for ( let i = 0; i < symbolNumber; ++i )
        {
            symbols.push( this.RandomSymbol() );
        }
        return symbols;
    }

    /**
     * @ch 最後一道防線 - 確保最終符號只設定一次
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param node 列符號
     * @param isStop 是否停輪
     */
    CheckChangeToFinalSymbol( col: number, node: ColumnSymbol, isStop = false )
    {
        if ( !this.m_isChangeToFinalSymbol[ col ] )
        {
            this.m_isChangeToFinalSymbol[ col ] = true;
            this.ChangeSymbol( col, node, isStop );
        }
    }

    /**
     * @ch 確認停輪效果(亞瑟王音效與動態分開)
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     */
    CheckPlayStopSoundAndEffect(col: number) {
        if (!this.m_isPlayStopSound[col]) {
            this.m_isPlayStopSound[col] = true;
            if (this.m_isClickStopBtn) {
                this.m_isPlayStopSound.fill( true );
            }
            this.PlayReelSound();
        }
    }

    /**
     * @ch 設置當局盤面資料，並設置停輪時間
     * @param content 當局盤面資料
     */
    SetPlateInfo( content: protocol.ar2esProto.ICColumn[] )
    {
        console.error( "This Plate is ", content );

        this.m_plateInfo = RecoverSpinAck.getInstance().ConvertPlate( content );

        // 直接處理並保留完整的 CSymbol 資料結構，避免多次轉換導致的資料失真
        this.m_plateInfoWithFakeSymbol = this.PreprocessPlateDataForServer( this.m_plateInfo );

        if (this.m_entryStrategy) {
            // DropEntry 模式：從 plateInfo 設定掉入資料
            this.SetDropResultFromPlateInfo();
        } else if ( !this.m_gameView.IsMgOmen ) {
            // 標準轉輪模式：設定停輪時間
            this.SetReelTimes();
        }
    }

    /**@ch 設定盤面Symbol For Unshow */
    SetPlateSymbolForUnshow( content: protocol.ar2esProto.ICColumn[] )
    {
        this.m_plateInfo = RecoverSpinAck.getInstance().ConvertPlate( content );

        // 直接處理並保留完整的 CSymbol 資料結構，避免多次轉換導致的資料失真
        this.m_plateInfoWithFakeSymbol = this.PreprocessPlateDataForServer( this.m_plateInfo );

        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            const symbolInfos = this.ConvertCSymbolsToSymbolInfos( this.m_plateInfoWithFakeSymbol[ col ].Col );
            this.m_allColumns[ this.MiddlePlateIndex ][ col ].SetSymbolInfos( symbolInfos );
        }
    }

    /**
     * @ch 預處理盤面資料：統一符號數量並保留完整 CSymbol 結構
     * @param serverData 原始服務器資料
     * @returns 預處理後的完整盤面資料（包含真實符號和假符號標記）
     */
    private PreprocessPlateDataForServer( serverData: protocol.ar2esProto.CColumn[] ): protocol.ar2esProto.CColumn[]
    {
        const processedData: protocol.ar2esProto.CColumn[] = [];

        // 檢查輸入有效性
        if (!serverData || !Array.isArray(serverData)) {
            error("PreprocessPlateDataForServer: Invalid serverData");
            // 返回預設的空盤面
            for (let col = 0; col < Game_Define.COL; col++) {
                const targetCount = this.GetTargetSymbolCount(col);
                const emptyColumn = new protocol.ar2esProto.CColumn();
                emptyColumn.Col = [];
                for (let i = 0; i < targetCount; i++) {
                    const fakeSymbol = this.GenerateFakeCSymbol([], col);
                    emptyColumn.Col.push(fakeSymbol);
                }
                processedData.push(emptyColumn);
            }
            return processedData;
        }

        for ( let col = 0; col < Game_Define.COL; col++ )
        {
            // 安全地取得列資料 - CColumn 結構中每個 Col 項目包含 CSymbol 物件
            const sourceColumn = (col < serverData.length && serverData[col]) ? serverData[col] : null;
            const targetCount = this.GetTargetSymbolCount( col );
            const processedColumn = new protocol.ar2esProto.CColumn();
            processedColumn.Col = [];

            // 保留原始伺服器的 CSymbol 資料（包含 JPState 和 Number）
            if (sourceColumn && sourceColumn.Col && Array.isArray(sourceColumn.Col)) {
                for (let i = 0; i < sourceColumn.Col.length && i < targetCount; i++) {
                    const originalCSymbol = sourceColumn.Col[i];
                    if (originalCSymbol) {
                        // 創建新的 CSymbol 並深度複製原始資料
                        const preservedSymbol = new protocol.ar2esProto.CSymbol();
                        preservedSymbol.Symbol = originalCSymbol.Symbol || 0;
                        preservedSymbol.JPState = originalCSymbol.JPState || 0;
                        preservedSymbol.Number = originalCSymbol.Number || 0;
                        processedColumn.Col.push(preservedSymbol);
                    }
                }
            }

            // 補充假符號至目標數量
            const existingSymbols = processedColumn.Col.map(cs => cs.Symbol);
            for (let i = processedColumn.Col.length; i < targetCount; i++)
            {
                const fakeSymbol = this.GenerateFakeCSymbol(existingSymbols, col);
                processedColumn.Col.push(fakeSymbol);
            }

            processedData.push( processedColumn );
        }

        return processedData;
    }

    /**
     * @ch 取得目標符號數量
     * @param columnIndex 列索引 (0 ~ Game_Define.COL-1)
     * @returns 目標符號數量
     */
    private GetTargetSymbolCount( columnIndex: number ): number
    {
        return ( this.m_layoutConfig.columns[ columnIndex ] || FALLBACK_COLUMN_CONFIG ).targetSymbolCount;
    }

    /**
     * @ch 取得可見符號數量
     * @param columnIndex 列索引 (0 ~ Game_Define.COL-1)
     * @returns 可見符號數量
     */
    private GetVisibleSymbolCount( columnIndex: number ): number
    {
        return ( this.m_layoutConfig.columns[ columnIndex ] || FALLBACK_COLUMN_CONFIG ).visibleSymbolCount;
    }

    /**
     * 根據一維位置索引取得行列座標
     * @param position 一維位置索引 (0 ~ N-1)
     * @returns {col: number, row: number}
     */
    GetColRowFromPosition(position: number): { col: number, row: number } {
        // 檢查輸入有效性
        if (!this.m_middleSymbolEmptyNodes || position < 0 || position >= this.m_middleSymbolEmptyNodes.length) {
            error(`GetColRowFromPosition: Invalid position ${position}`);
            return { col: 0, row: 0 };
        }

        // 根據 m_MiddleSymbolEmptyNodes 的索引順序計算行列座標
        let currentIndex = 0;
        for (let col = 0; col < Game_Define.COL; col++) {
            const visibleSymbolCount = this.GetVisibleSymbolCount(col);
            if (position < currentIndex + visibleSymbolCount) {
                const row = position - currentIndex;
                return { col, row };
            }
            currentIndex += visibleSymbolCount;
        }

        // 如果到這裡，說明計算有誤
        error(`GetColRowFromPosition: Unable to calculate position ${position}`);
        return { col: 0, row: 0 };
    }

    /**
     * 根據行列座標取得一維位置索引
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param row 行索引 (0 ~ visibleSymbolCount-1)
     * @returns 一維位置索引 (0 ~ N-1)，無效時回傳 -1
     */
    GetPositionFromColRow(col: number, row: number): number {
        // 檢查輸入有效性
        if (col < 0 || col >= Game_Define.COL) {
            error(`GetPositionFromColRow: Invalid col ${col}`);
            return -1;
        }

        const visibleSymbolCount = this.GetVisibleSymbolCount(col);
        if (row < 0 || row >= visibleSymbolCount) {
            error(`GetPositionFromColRow: Invalid row ${row} for col ${col} (max: ${visibleSymbolCount - 1})`);
            return -1;
        }

        // 計算該行列座標對應的一維位置索引
        let position = 0;
        for (let c = 0; c < col; c++) {
            position += this.GetVisibleSymbolCount(c);
        }
        position += row;

        // 檢查計算結果是否在有效範圍內
        if (!this.m_middleSymbolEmptyNodes || position >= this.m_middleSymbolEmptyNodes.length) {
            error(`GetPositionFromColRow: Calculated position ${position} is out of range`);
            return -1;
        }

        return position;
    }

    /**
     * 根據一維位置索引取得中間符號的空Node
     * @param position 一維位置索引 (0 ~ N-1)
     * @returns 中間符號的空Node
     */
    GetMiddleSymbolEmptyNodeFromPosition(position: number): Node {
        return this.m_middleSymbolEmptyNodes[position];
    }

    /**
     * 根據行列座標取得中間符號的空Node
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param row 行索引 (0 ~ visibleSymbolCount-1)
     * @returns 中間符號的空Node
     */
    GetMiddleSymbolEmptyNodeFromColRow(col: number, row: number): Node {
        const position = this.GetPositionFromColRow(col, row);
        return this.m_middleSymbolEmptyNodes[position];
    }

    /**
     * 根據行列座標取得符號的世界座標位置
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param row 行索引 (0 ~ visibleSymbolCount-1)
     * @returns 世界座標 Vec3，無效時回傳 v3(0, 0, 0)
     */
    GetSymbolInitWorldPositionFromColRow(col: number, row: number): Vec3 {        

        // 從對應的 EmptyNode 取得世界座標
        const emptyNode = this.GetMiddleSymbolEmptyNodeFromColRow(col, row);
        if (!emptyNode || !emptyNode.isValid) {
            error(`GetSymbolInitWorldPosition: EmptyNode at col ${col}, row ${row} is invalid`);
            return v3(0, 0, 0);
        }

        // 轉換為世界座標
        const worldPosition = emptyNode.getWorldPosition();
        return worldPosition;
    }

    /**
     * 根據一維位置索引取得中間符號的空Node的世界座標
     * @param position 一維位置索引 (0 ~ N-1)
     * @returns 世界座標 Vec3，無效時回傳 v3(0, 0, 0)
     */
    GetSymbolInitWorldPositionFromPosition(position: number): Vec3 {
        const emptyNode = this.GetMiddleSymbolEmptyNodeFromPosition(position);
        if (!emptyNode || !emptyNode.isValid) {
            error(`GetSymbolInitWorldPosition: EmptyNode at position ${position} is invalid`);
            return v3(0, 0, 0);
        }
        const worldPosition = emptyNode.getWorldPosition();
        return worldPosition;
    }

    /**
     * 根據行列座標取得符號的本地座標位置
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param row 行索引 (0 ~ visibleSymbolCount-1)
     * @returns 世界座標 Vec3，無效時回傳 v3(0, 0, 0)
     */
    GetSymbolInitLocalPositionFromColRow(col: number, row: number): Vec3 {        

        // 從對應的 EmptyNode 取得世界座標
        const emptyNode = this.GetMiddleSymbolEmptyNodeFromColRow(col, row);
        if (!emptyNode || !emptyNode.isValid) {
            error(`GetSymbolInitLocalPosition: EmptyNode at col ${col}, row ${row} is invalid`);
            return v3(0, 0, 0);
        }

        // 轉換為世界座標
        const worldPosition = emptyNode.getPosition();
        return worldPosition;
    }

    /**
     * 根據行列座標取得對應的 SingleCell
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param row 行索引 (0 ~ visibleSymbolCount-1)
     * @returns SingleCell 或 null
     */
    GetSingleCellFromColRow(col: number, row: number): SingleCell | null {
        if (!this.m_allColumns || this.m_allColumns.length === 0 || col < 0 || col >= Game_Define.COL) {
            return null;
        }

        const middlePlateIndex = this.MiddlePlateIndex;
        if (middlePlateIndex >= this.m_allColumns.length) {
            return null;
        }

        const column = this.m_allColumns[middlePlateIndex][col];
        if (!column) {
            return null;
        }

        return column.GetSingleCell(row);
    }

    /**
     * 根據一維位置索引取得符號的本地座標位置
     * @param position 一維位置索引 (0 ~ N-1)
     * @returns 本地座標 Vec3，無效時回傳 v3(0, 0, 0)
     */
    GetSymbolInitLocalPositionFromPosition(position: number): Vec3 {
        const emptyNode = this.GetMiddleSymbolEmptyNodeFromPosition(position);
        if (!emptyNode || !emptyNode.isValid) {
            error(`GetSymbolInitLocalPosition: EmptyNode at position ${position} is invalid`);
            return v3(0, 0, 0);
        }
        const worldPosition = emptyNode.getPosition();
        return worldPosition;
    }

    /**@ch 生成假符號 CSymbol（帶有標記）
     * @param existingSymbols 現有符號 ID 陣列
     * @param columnIndex 列索引 (0 ~ Game_Define.COL-1)
     * @returns 帶有假符號標記的 CSymbol
     */
    private GenerateFakeCSymbol( existingSymbols: number[], columnIndex: number ): protocol.ar2esProto.CSymbol
    {
        const fakeSymbol = new protocol.ar2esProto.CSymbol();

        const strategy = this.m_layoutConfig.fakeSymbolStrategy;

        switch ( strategy )
        {
            case 'repeat':
                // 重複現有符號
                if ( existingSymbols.length > 0 )
                {
                    const randomIndex = Math.floor( Math.random() * existingSymbols.length );
                    fakeSymbol.Symbol = existingSymbols[ randomIndex ];
                }
                else
                {
                    fakeSymbol.Symbol = this.GetRandomSymbolByWeight();
                }
                break;

            case 'random':
            default:
                // 使用隨機符號（按照原本的符號權重）
                fakeSymbol.Symbol = this.GetRandomSymbolByWeight();
                break;
        }

        // 標記為假符號：使用 JPState = -1 來識別假符號
        fakeSymbol.JPState = -1;  // 特殊標記：-1 表示這是假符號
        fakeSymbol.Number = 0;    // 假符號沒有額外數值

        return fakeSymbol;
    }

    /**@ch 生成假符號（向後相容的版本，僅返回符號 ID）
     * @param existingSymbols 現有符號
     * @param columnIndex 列索引 (0 ~ Game_Define.COL-1)
     * @returns 假符號 ID
     */
    private GenerateFakeSymbol( existingSymbols: number[], columnIndex: number ): number
    {
        const fakeCSymbol = this.GenerateFakeCSymbol(existingSymbols, columnIndex);
        return fakeCSymbol.Symbol;
    }

    /**@ch 按權重取得隨機符號 */
    private GetRandomSymbolByWeight(): number
    {
        // 簡化實現：隨機返回基本符號
        // 這裡可以根據遊戲需求實現更複雜的權重邏輯
        return Math.floor( Math.random() * 12 ); // 0-11的基本符號
    }

    /**@ch 將符號ID陣列轉換為SymbolInfo陣列。
     * SymbolInfo 物件取自 m_pooledSymbolInfos 共用池避免 GC 壓力；外層 Array 仍每次新建以保持 `.length` 正確。
     * ⚠️ 回傳陣列中的 SymbolInfo 跨呼叫共用，呼叫端必須在下次呼叫前消費完。
     * @param symbols 符號ID陣列
     * @returns SymbolInfo陣列
     */
    private ConvertSymbolsToSymbolInfos( symbols: number[] ): SymbolInfo[]
    {
        const len = symbols.length;
        while ( this.m_pooledSymbolInfos.length < len )
        {
            this.m_pooledSymbolInfos.push( new SymbolInfo() );
        }
        const result: SymbolInfo[] = new Array( len );
        for ( let i = 0; i < len; ++i )
        {
            const info = this.m_pooledSymbolInfos[ i ];
            info.Symbol = symbols[ i ];
            info.Value = 0;
            info.JpType = 0;
            result[ i ] = info;
        }
        return result;
    }

    /**@ch 將CSymbol陣列轉換為SymbolInfo陣列
     * @param cSymbols ICSymbol陣列
     * @returns SymbolInfo陣列
     */
    private ConvertCSymbolsToSymbolInfos( cSymbols: protocol.ar2esProto.ICSymbol[] ): SymbolInfo[]
    {
        return cSymbols.map( cSymbol => {
            let symbolInfo = new SymbolInfo();
            symbolInfo.Symbol = cSymbol.Symbol;
            symbolInfo.Value = cSymbol.Number || 0;
            symbolInfo.JpType = cSymbol.JPState || 0;
            return symbolInfo;
        });
    }

    /**@ch 調整所有 ColumnSymbol 的符號數量 */
    private AdjustColumnSymbolCounts()
    {
        for ( let layer = 0; layer < this.m_allColumns.length; layer++ )
        {
            for ( let col = 0; col < this.m_allColumns[ layer ].length; col++ )
            {
                const targetCount = this.GetTargetSymbolCount( col );
                const columnSymbol = this.m_allColumns[ layer ][ col ];

                if ( columnSymbol && columnSymbol.ResizeSymbolCount )
                {
                    columnSymbol.ResizeSymbolCount( targetCount );
                }
            }
        }

        // 重新計算所有相關的位置和長度數據
        this.UpdateTotalLengths();
        this.UpdateReelYPositions();
        this.UpdateComparePosArray();
    }

    /**@ch 更新轉輪總長度計算 */
    private UpdateTotalLengths()
    {
        if ( !this.m_symbolSize )
        {
            return; // 尚未初始化
        }

        for ( let col = 0; col < Game_Define.COL; col++ )
        {
            const actualSymbolCount = this.GetTargetSymbolCount( col );
            this.m_totalLengths[ col ] = actualSymbolCount * this.m_symbolSize.height * this.m_layoutConfig.plateCount;
        }
    }

    /**@ch 更新轉輪Y位置陣列計算 */
    private UpdateReelYPositions()
    {
        if ( !this.m_symbolSize )
        {
            return; // 尚未初始化
        }

        // 清空並重新計算 Y 位置陣列
        this.m_reelYPosAry = [];

        // 找出最高的 viewHeight 作為 top/bottom 對齊的參考線
        let maxViewHeight = 0;
        for ( let c = 0; c < Game_Define.COL; ++c )
        {
            const vH = this.CalViewHeightInCol( c );
            if ( vH > maxViewHeight ) maxViewHeight = vH;
        }

        const plateCount = this.m_layoutConfig.plateCount;
        // center = MiddlePlateIndex + 0.5，讓中層 plate 永遠落在 -0.5 viewHeight 位置
        //   plateCount=3：MiddlePlateIndex=1 → center=1.5（下-1.5 / 中-0.5 / 上+0.5）
        //   plateCount=1：MiddlePlateIndex=0 → center=0.5（唯一一層 -0.5 與原中層對齊）
        const center = this.MiddlePlateIndex + 0.5;
        const alignment = this.m_layoutConfig.columnAlignment ?? 'center';

        // 重新計算(下、中、上)每個轉輪的Y座標
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            let ary = new Array<number>();
            const viewHeight = this.CalViewHeightInCol( col );

            // 對齊偏移：以「最高列在 center 對齊下的視覺範圍」為基準
            //   'center'：偏移 0，每列各自置中
            //   'top'   ：短列往上推 (max-self)/2，所有列頂端對齊
            //   'bottom'：短列往下拉 (max-self)/2，所有列底端對齊
            let alignmentOffset = 0;
            switch ( alignment )
            {
                case 'top':
                    alignmentOffset = ( maxViewHeight - viewHeight ) / 2;
                    break;
                case 'bottom':
                    alignmentOffset = -( maxViewHeight - viewHeight ) / 2;
                    break;
                case 'center':
                default:
                    alignmentOffset = 0;
                    break;
            }

            for ( let plate = 0; plate < plateCount; ++plate )
            {
                ary.push( viewHeight * ( plate - center ) + alignmentOffset );
            }
            this.m_reelYPosAry.push( ary );
        }
    }

    /**@ch 計算並更新所有轉輪的X座標位置
     * @param middleMaskNodeViewSize 中間遮罩Node視窗大小
     */
    private UpdateReelXPositions( middleMaskNodeViewSize: Size ): void
    {
        this.m_reelXPos = []; // 清空現有陣列

        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            this.m_reelXPos.push(
                this.m_symbolSize.width * ( col + 0.5 )
                - middleMaskNodeViewSize.width / 2
                + Game_Define.SeparateLineWidth * col
                + this.m_reelPositionOffset[ col ].x
            );
        }
    }

    /**@ch 更新比較位置陣列計算 */
    private UpdateComparePosArray()
    {
        if ( !this.m_symbolSize )
        {
            return; // 尚未初始化
        }

        // 清空並重新計算比較位置陣列
        this.m_comparePosAry = [];

        // 重新計算(下、中、上)每個轉輪的比較(交換符號)位置
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            let posAry = new Array<number>();
            for ( let plate = 0; plate < this.m_layoutConfig.plateCount; ++plate )
            {
                posAry.push( this.CalComparePos( col, plate ) ); // 現在會使用實際符號數量
            }
            this.m_comparePosAry.push( posAry );
        }
    }

    /**@ch 設置停輪時間相關設定
     * @param timesOfSpin 轉輪圈數
     */
    SetReelTimes( timesOfSpin?: number)
    {
        let riseTime = this.m_totalRiseTime;
        if ( !timesOfSpin )
        {
            if ( this.m_gameView.IsMgOmen )
            {
                return;
            }

            timesOfSpin = Math.ceil( ( this.m_time - riseTime ) / this.m_spinTime );
            timesOfSpin = timesOfSpin !== 0 ? timesOfSpin : 1; // || 1
        }

        let lockCount = 0;
        if ( this.m_isClickStopBtn )
        {
            // 規格有Rise的話，快停仍有Rise(可參考上海甜心)
            this.StopTime = this.ToolsStrip( this.m_spinTime * timesOfSpin + this.m_spinDelayTime + riseTime );
            let reelStopTime = this.ToolsStrip( this.m_spinTime * timesOfSpin );
            let reelPreTime = this.ToolsStrip( this.m_spinTime * ( timesOfSpin - 1 ) );
            for ( let i = 0; i < Game_Define.COL; ++i )
            {
                if ( this.m_lockColumn[ i ] )
                {
                    // 鎖定的轉輪立即停止
                    this.m_reelStopTime[ i ] = 0;
                    this.m_reelPreTime[ i ] = 0;
                }
                else
                {
                    this.m_reelStopTime[ i ] = reelStopTime;
                    this.m_reelPreTime[ i ] = reelPreTime;
                }
            }
        }
        else
        {
            // NearWin：重置偵測器，計算是否觸發
            this.m_nearWinDetector?.Reset();

            // 先計算所有輪的停輪時間
            for ( let col = 0; col < Game_Define.COL; ++col )
            {
                if ( this.m_lockColumn[ col ] )
                {
                    // 鎖定的轉輪立即停止
                    this.m_reelStopTime[ col ] = 0;
                    this.m_reelPreTime[ col ] = 0;
                    ++lockCount;
                }
                else
                {
                    // NearWin 額外圈數
                    const extraSpins = this.m_nearWinDetector?.GetExtraSpins(col, this.m_plateInfo) ?? 0;
                    let adjustedTimes = timesOfSpin + extraSpins;

                    // 設定每一輪的停輪時間
                    let stopTime = this.CalculateReelStopTime(col, adjustedTimes, lockCount);

                    this.m_reelStopTime[ col ] = stopTime;
                    this.m_reelPreTime[ col ] = this.ToolsStrip( stopTime - this.m_spinTime );
                }
            }

            // StopTime 應該等於最後一輪的停輪時間（加上緩衝時間）
            let lastReelStopTime = 0;
            for (let col = 0; col < Game_Define.COL; ++col) {
                if (!this.m_lockColumn[col] && this.m_reelStopTime[col] > lastReelStopTime) {
                    lastReelStopTime = this.m_reelStopTime[col];
                }
            }

            // StopTime = 最後一輪停輪時間 + 緩衝時間
            // 這樣確保所有輪都停下來後，再等待一小段緩衝時間就結束
            this.StopTime = this.ToolsStrip(
                lastReelStopTime + this.m_spinBufferTime01 + this.m_spinBufferTime02
            );
        }
    }

    /**@ch 壓黑盤面
     * @param isDark 是否壓黑
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     */
    SetSymbolDark( isDark: boolean, col: number )
    {
        for ( let column = 0; column < Game_Define.COL; ++column )
        {
            if ( column === col )
            {
                for ( let i = 0; i < this.m_layoutConfig.plateCount; ++i )
                {
                    this.m_allColumns[ i ][ column ].SetSymbolDark( false );
                }
                continue;
            }
            for ( let i = 0; i < this.m_layoutConfig.plateCount; ++i )
            {
                this.m_allColumns[ i ][ column ].SetSymbolDark( isDark );
            }
        }
    }

    /**@ch 檢查此Column已經是否停輪
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @returns 是否停輪
     */
    CheckColIsStop( col: number )
    {
        return this.m_time >= this.m_reelStopTime[ col ];
    }

    /**@ch 計算該位移到哪 */
    CalculateSpinPos(
        //  totalLength: number, totalTime: number, curTime: number, oneLapTime: number
    )
    {

    }

    /**
     * @ch 隱藏靜態全盤面
     * @param delayTime 延遲時間
     */
    async HidePlate( delayTime = 0 )
    {
        await Define.Wait( this, delayTime );
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            this.AllColumns[ this.MiddlePlateIndex ][ col ].SetColumnVisiable( false );
        }
