     *              plateCount=1：plate 0 → role 1 → ""（唯一一層永遠是中層）
     */
    private GetPlateNamePrefix(plate: number): string {
        const role = plate - this.MiddlePlateIndex + 1;
        return Game_Define.NODE_PREFIX_NAME[role] ?? "";
    }

    /**@ch 盤面資料(不包含假符號) 現在統一直接使用Proto架構 */
    private m_plateInfo: Array<protocol.ar2esProto.CColumn> = new Array<protocol.ar2esProto.CColumn>();
    public get PlateInfo()
    {
        return this.m_plateInfo;
    }

    /**@ch 完整盤面資料（包含真實符號和假符號標記）
     * 保留原始 CSymbol 的所有屬性：Symbol、JPState、Number
     * JPState = -1 表示假符號，JPState >= 0 表示真實符號
     */
    private m_plateInfoWithFakeSymbol: Array<protocol.ar2esProto.CColumn> = new Array<protocol.ar2esProto.CColumn>();
    public get PlateInfoWithFakeSymbol()
    {
        return this.m_plateInfoWithFakeSymbol;
    }

    /**@ch 可重用的 Vec3 物件，避免每幀創建新物件造成 GC 壓力 */
    private m_tempVec3: Vec3 = new Vec3();

    /**@ch SymbolInfo 物件池：ConvertSymbolsToSymbolInfos 從這裡取用而非每次 new SymbolInfo()。
     * 按需擴張、長度保留最大值。⚠️ 同一索引的 SymbolInfo 跨呼叫共用，呼叫端必須在下次呼叫前同步消費完上一次的回傳結果。 */
    private m_pooledSymbolInfos: SymbolInfo[] = [];

    /**@ch 各列轉一圈時間的快取（isNearWin=false 情境），於 StartSpin 預算。
     * 依賴 m_spinTime（onLoad 後不變）與 GetTargetSymbolCount（spin 期間不變），故 spin 期間可安心讀取。
     * isNearWin=true 的情境目前未啟用；若未來啟用須現算或加第二個 cache。 */
    private m_cachedSpinTimes: number[] = new Array( Game_Define.COL ).fill( 0 );

    /**@ch 取得真正盤面資料中指定位置的符號 */
    GetSymbolInRealPlateInfo( col: number, row: number ): protocol.ar2esProto.ICSymbol
    {
        if ( col < 0 || col >= this.m_plateInfo.length || row < 0 || row >= this.m_plateInfo[ col ].Col.length )
        {
            return null;
        }

        return this.m_plateInfo[ col ].Col[ row ];
    }

    /**@ch 取得真正盤面資料中指定位置的符號 */
    GetSymbolInRealPlateInfoByPosition( position: number ): protocol.ar2esProto.ICSymbol
    {
        const { col, row } = this.GetColRowFromPosition( position );

        return this.GetSymbolInRealPlateInfo( col, row );
    }

    private m_reelPositionOffset: Vec3[] = [
        v3( 0, 0 ),
        v3( 0, 0 ),
        v3( 0, 0 ),
        v3( 0, 0 ),
        v3( 0, 0 ),
        v3( 0, 0 ),
    ];

    // Sound
    private m_isPlayStopSound: boolean[] = new Array( Game_Define.COL ).fill( false );
    private m_isPlayStopEffect: boolean[] = new Array( Game_Define.COL ).fill( false );
    private m_reelSoundId: number = null;

    private m_isPlayingEffect = false;
    public get IsPlayingEffect()
    {
        return this.m_isPlayingEffect;
    }

    private m_gameView: GameView = null;
    private m_nearWinDetector: NearWinDetector = null;

    /**@ch 是否已經初始化值 */
    private m_isInitValueFinish = false;

    /**@ch 中間輪帶空符號節點 */
    private m_middleSymbolEmptyNodes: Node[] = [];

    /**
     * @ch 計算比較(交換符號)位置
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param plate 盤面索引 (0 ~ plateCount-1)
     * @returns 比較(交換符號)位置
     */
    CalComparePos(col: number, plate: number) : number
    {
        return this.CalViewHeightInCol(col) * (this.m_reelDirection === ReelDirection.Down ? plate : this.m_layoutConfig.plateCount - plate - 1);
    }

    /**
     * @ch 計算該轉輪View高度 - 彈性轉輪系統修正
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @returns 轉輪View高度
     */
    CalViewHeightInCol( col: number ) : number
    {
        if ( col < 0 || col >= Game_Define.COL )
        {
            return 0;
        }

        // 使用實際符號數量而非固定的 ROW_CONFIG
        const actualSymbolCount = this.GetTargetSymbolCount( col );
        return this.m_symbolSize.height * actualSymbolCount;
    }    

    /**
     * @ch 取得該轉輪總長度
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @returns 轉輪總長度
     */
    GetTotalLength( col: number ) : number
    {
        return this.m_totalLengths[ col ];
    }

    /**
     * @ch 取得該轉輪比較(交換符號)位置
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param plate 盤面索引 (0 ~ plateCount-1)
     * @returns 轉輪比較(交換符號)位置
     */
    GetComparePos( col: number, plate: number ) : number
    {
        return this.m_comparePosAry[ col ][ plate ];
    }

    /**
     * @ch 取得該轉輪Y座標
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param plate 盤面索引 (0 ~ plateCount-1)
     * @returns 轉輪Y座標
     */
    GetReelYPos( col: number, plate: number ) : number
    {
        let offset = ( col >= 0 && col < this.m_reelYOffset.length ) ? this.m_reelYOffset[ col ] : 0;
        return this.m_reelYPosAry[ col ][ plate ] + offset;
    }

    /**
     * @ch 設定所有轉輪Y座標偏移量
     * @param offset 轉輪Y座標偏移量
     */
    SetAllReelYOffset( offset: number )
    {
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            this.m_reelYOffset[ col ] = offset;
        }
        // 更新所有現有符號的位置
        this.UpdateAllSymbolPositions();
    }

    /**
     * @ch 設定特定轉輪Y座標偏移量
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param offset 轉輪Y座標偏移量
     */
    SetReelYOffset( col: number, offset: number )
    {
        if ( col >= 0 && col < Game_Define.COL )
        {
            this.m_reelYOffset[ col ] = offset;
            // 只更新該列的符號位置
            this.UpdateColumnSymbolPositions( col );
        }
    }

    /**
     * @ch 設定多個轉輪Y座標偏移量
     * @param offsets 轉輪Y座標偏移量
     */
    SetMultipleReelYOffset( offsets: number[] )
    {
        for ( let col = 0; col < Math.min( offsets.length, Game_Define.COL ); ++col )
        {
            this.m_reelYOffset[ col ] = offsets[ col ];
        }
        // 更新所有現有符號的位置
        this.UpdateAllSymbolPositions();
    }

    /**
     * @ch 更新所有符號位置（應用Y偏移量）
     */
    private UpdateAllSymbolPositions()
    {
        if ( !this.m_allColumns || this.m_allColumns.length === 0 )
        {
            return; // 尚未創建符號
        }

        // 遍歷所有盤面 (下、中、上)
        for ( let plate = 0; plate < this.m_layoutConfig.plateCount; ++plate )
        {
            if ( !this.m_allColumns[ plate ] )
            {
                continue;
            }

            // 遍歷每列
            for ( let col = 0; col < Game_Define.COL; ++col )
            {
                if ( this.m_allColumns[ plate ][ col ] )
                {
                    // 重新設定符號位置，GetReelYPos 會自動應用偏移量
                    let newPosition = v3( this.m_reelXPos[ col ], this.GetReelYPos( col, plate ) );
                    this.m_allColumns[ plate ][ col ].SetPosition( newPosition );
                }
            }
        }
    }

    /**
     * @ch 更新特定列的符號位置（應用Y偏移量）
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     */
    private UpdateColumnSymbolPositions( col: number )
    {
        if ( !this.m_allColumns || this.m_allColumns.length === 0 || col < 0 || col >= Game_Define.COL )
        {
            return; // 尚未創建符號或無效列索引
        }

        // 遍歷該列的所有盤面 (下、中、上)
        for ( let plate = 0; plate < this.m_layoutConfig.plateCount; ++plate )
        {
            if ( this.m_allColumns[ plate ] && this.m_allColumns[ plate ][ col ] )
            {
                // 重新設定符號位置，GetReelYPos 會自動應用該列的偏移量
                let newPosition = v3( this.m_reelXPos[ col ], this.GetReelYPos( col, plate ) );
                this.m_allColumns[ plate ][ col ].SetPosition( newPosition );
            }
        }
    }

    /**
     * @ch 取得特定轉輪Y座標偏移量
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @returns 轉輪Y座標偏移量
     */
    GetReelYOffset( col: number ): number
    {
        if ( col >= 0 && col < this.m_reelYOffset.length )
        {
            return this.m_reelYOffset[ col ];
        }
        return 0;
    }

    /**
     * @ch 取得所有轉輪Y座標偏移量
     * @returns 所有轉輪Y座標偏移量
     */
    GetAllReelYOffset(): number[]
    {
        return [...this.m_reelYOffset]; // 回傳副本
    }

    /**
     * @ch 取得滾動方向係數
     * @returns 1 表示向上，-1 表示向下
     */
    private GetDirectionMultiplier(): number
    {
        return this.m_reelDirection === ReelDirection.Up ? 1 : -1;
    }

    /**
     * @ch 計算該轉輪轉一圈時間 - 彈性轉輪系統修正
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param isNearWin 是否為近贏
     * @returns 轉一圈時間
     */
    CalSpinTime(col: number, isNearWin: boolean) : number
    {
        // 使用實際符號數量而非固定的 ROW_CONFIG
        const actualSymbolCount = this.GetTargetSymbolCount( col );
        return this.m_spinTime * ( actualSymbolCount / Game_Define.MAX_ROW ) / ( isNearWin ? NEARWIN_SPIN_SPEED_UP : 1 );
    }

    /**
     * @ch 把錯誤的數據轉正
     * @param num 數字
     * @param precision 精度
     * @returns 轉正後的數字
     */
    ToolsStrip( num: number, precision?: number ) : number
    {
        try
        {
            // 優先使用 tools.strip 方法
            if ( tools && typeof tools.strip === 'function' )
            {
                return tools.strip( num, precision );
            }
        }
        catch ( error )
        {
            console.warn( "tools.strip 無法使用，使用備用方法:", error );
        }

        // 備用實作：處理浮點數精度問題
        if ( typeof num !== 'number' || isNaN( num ) )
        {
            return num;
        }

        // 如果沒有指定精度，使用預設精度 12
        const defaultPrecision = precision !== undefined ? precision : 12;

        // 使用 parseFloat 和 toPrecision 來處理精度問題
        const result = parseFloat( num.toPrecision( defaultPrecision ) );

        return result;
    }

    /**
     * @ch 計算點擊停止按鈕後的轉輪停止時間
     * @param time 時間
     * @returns 轉輪停止時間
     */
    CalClickStopButtonFinishTime( time: number ) : number
    {
        let timeOfSpine = Math.ceil( time / this.m_spinTime );
        let stopTime = 0;
        if (tempoSetting)
        {
            stopTime = tempoSetting.TempoSetting.TripleCoinTreasure.SPEED_UP_STOP_TIME( 0, time );
        }
        else
        {
            stopTime = ( timeOfSpine + 2 ) * this.m_spinTime;
        }
        return this.ToolsStrip( stopTime );
    }

    /**@ch 初始化值 */
    InitValue()
    {
        if ( this.m_isInitValueFinish )
        {
            return;
        }

        this.m_viewSize = this.node.getComponent( UITransform ).contentSize;

        this.m_symbolSize = new Size( Game_Define.SymbolWidth, Game_Define.SymbolHeight );

        // 計算(下、中、上)每個轉輪的比較(交換符號)位置
        this.UpdateComparePosArray();

        // 初始化各轉輪Y座標偏移量
        this.m_reelYOffset = [];
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            this.m_reelYOffset[ col ] = ( col < this.m_reelYOffsetProperty.length ) ? this.m_reelYOffsetProperty[ col ] : 0;
        }

        // 計算(下、中、上)每個轉輪的Y座標
        this.UpdateReelYPositions();

        // 計算並更新所有轉輪的X座標位置
        const middleMaskNode = this.m_reelMask;
        const middleMaskNodeViewSize = middleMaskNode.getComponent( UITransform ).contentSize;
        this.UpdateReelXPositions( middleMaskNodeViewSize );

        // 計算每轉輪(下、中、上相加)總長度 - 彈性轉輪系統修正
        this.UpdateTotalLengths();

        this.m_isInitValueFinish = true;
    }

    onLoad()
    {
        // 轉輪節奏模組：三幣瑞龍
        let tempoSettingCb = () =>
        {
            let tempoModule = tempoSetting?.TempoSetting.TripleCoinTreasure;
            if ( !tempoModule )
            {
                return;
            }
            this.m_riseTime = tempoModule.BASE.RISE_TIME;
            this.m_totalRiseTime = this.m_riseTime * Game_Define.COL;
            this.m_upLength = tempoModule.BASE.UP_LENGTH;
            this.m_spinBufferTime01 = tempoModule.BASE.SPIN_BUFFER_TIME_01;
            this.m_spinBufferTime02 = tempoModule.BASE.SPIN_BUFFER_TIME_02;
            this.m_downLength = tempoModule.BASE.DOWN_LENGTH;
            // this.m_spinTime = tempoModule.BASE.SPIN_SPEED;
            this.m_timesOfBaseSpin = tempoModule.BASE.TIMES_OF_BASE_SPIN;
            this.m_spinIntervalTimes = tempoModule.BASE.SPIN_INTERVAL_TIMES;
            this.m_spinDelayTime = tempoModule.BASE.SPIN_DELAY_TIME;
        };
        tempoSettingCb();
        tempoSetting?.AddCb( tempoSettingCb );
    }

    /**
     * @ch 初始化
     * @param gameView 遊戲視窗
     */
    Init( gameView: GameView )
    {
        this.m_gameView = gameView;
        this.m_nearWinDetector = new NearWinDetector(gameView.EffectPlate);
        this.InitValue();
    }

    /**@ch 設定初始盤面 */
    CreateSymbol()
    {
        // plate = 0 下，plate = 1 中，plate = 2 上
        for ( let plate = 0; plate < this.m_layoutConfig.plateCount; ++plate )
        {
            let arr = new Array<ColumnSymbol>;
            this.m_allColumns.push( arr );
        }

        // 因為圖層要下壓上，所以從上往下建盤面
        for ( let plate = this.m_layoutConfig.plateCount - 1; plate >= 0; --plate )
        {
            this.CreatePlate( plate );
        }

        this.m_isLoadingComplete = true;
    }

    /**
     * @ch 設定一個 ( COL X N ) 盤面 (N 由彈性轉輪系統修正)
     * @param plate 盤面索引 (0 ~ plateCount-1)
     */
    CreatePlate( plate: number )
    {
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            let colName = col.toString();
            let nodeName = this.GetPlateNamePrefix( plate ) + colName;
            // 根據實際符號數量創建 ColumnSymbol 由彈性轉輪系統修正
            let rowCount = this.GetTargetSymbolCount( col );
            const parentNode = this.m_reelMask;
            let columnSymbol = new ColumnSymbol( parentNode, this.m_gameView, nodeName, rowCount );
            columnSymbol.Name = nodeName;

            // 設定位置(需等InitValue後才能使用)
            columnSymbol.SetPosition( v3( this.m_reelXPos[ col ], this.GetReelYPos( col, plate ) ) );

            let symbols = new Array<number>();
            for ( let row = 0; row < rowCount; ++row )
            {
                let add = col;// row % 4;
                symbols.push( Game_Define.Symbol.A + add );
            }
            let symbolInfos = this.ConvertSymbolsToSymbolInfos( symbols );
            columnSymbol.SetSymbolInfos( symbolInfos );

            if ( plate === this.MiddlePlateIndex )
            {
                const visibleSymbolCount = this.GetVisibleSymbolCount( col );
                const columnData = symbols.slice( 0, visibleSymbolCount );

                this.m_plateInfo.push( RecoverSpinAck.getInstance().ConvertCColumn( columnData ) );

                // 創建中間符號的空Node
                for ( let i = 0; i < visibleSymbolCount; ++i )
                {
                    let middleSymbolEmptyNode = new Node();
                    middleSymbolEmptyNode.name = "Middle_" + col.toString() + i.toString();
                    middleSymbolEmptyNode.layer = Define.Layer2D;
                    parentNode.addChild(middleSymbolEmptyNode);
                    const symbolNode = columnSymbol.GetSymbolNodeAt( i );
                    middleSymbolEmptyNode.setPosition(symbolNode.position);
                    this.m_middleSymbolEmptyNodes.push(middleSymbolEmptyNode);
                }
            }
            this.m_allColumns[ plate ].push( columnSymbol );
        }
    }

