    /**
     * @ch 設定盤面結構配置
     * @param config 盤面結構配置（plateCount、每列 target/visible、假符號策略等）
     * @description
     *   建議在 GameView init 早期、CreateSymbol 之前呼叫一次。
     *   若在 CreateSymbol 之後改 config（例如切換 free game 用不同盤面），
     *   會自動重算 ColumnSymbol 大小、總長度與 Y 座標。
     *   注意：執行期切換不會改動 plateCount（上下假盤面已建/未建無法事後動態改）。
     */
    public SetLayoutConfig( config: ReelLayoutConfig )
    {
        this.m_layoutConfig = config;

        // 已建立盤面後才呼叫 → 重新調整現有 ColumnSymbol
        if ( this.m_plateInfo.length > 0 )
        {
            this.AdjustColumnSymbolCounts();
        }
        else
        {
            // 即使尚未建立盤面，也要更新位置 / 長度相關陣列
            this.UpdateTotalLengths();
            this.UpdateReelYPositions();
            this.UpdateComparePosArray();
        }
    }

