 * GameView 可經 SetPlateDesyncHandler 接上 ConnectionManager.SendErrorLog / 踢玩家，
 * 以保持 SlotReels 不直接依賴 framework 的連線/訊息框模組（解耦）。
 */
private m_onPlateDesync: PlateDesyncHandler | null = null;

/**
 * @ch 設定盤面對帳不一致的處理回呼（傳 null 取消）
 * @param handler 收到不一致 errorObj 時呼叫；null = 只 log
 */
SetPlateDesyncHandler( handler: PlateDesyncHandler | null )
{
    this.m_onPlateDesync = handler;
}

/**
 * @ch 檢查盤面是否正確：逐格比對 server 盤面與畫面顯示 symbol。
 * 不一致時每格 error() log；若已設定 desync handler 則額外回呼（由 GameView 決定上報/踢玩家）。
 */
CheckPlateInfo()
{
    if (!this.m_plateInfo || this.m_plateInfo.length === 0) {
        return;
    }

    let errorObj: PlateDesyncError = { errors: [] };
    let hasError = false;

    let serverSymbol = 0;
    let showSymbol = 0;
    for ( let col = 0; col < this.m_plateInfo.length; col++ )
    {
        for ( let row = 0; row < this.m_plateInfo[ col ].Col.length; row++ )
        {
            serverSymbol = this.m_plateInfo[ col ].Col[ row ].Symbol;
            showSymbol = this.m_allColumns[ this.MiddlePlateIndex ][ col ].Symbols[ row ];
            if ( serverSymbol !== showSymbol )
            {
                errorObj.errors.push( { col: col, row: row } );
                error( `盤面錯誤: col=${col}, row=${row} ServerSymbol = ${serverSymbol} 畫面Symbol = ${showSymbol}` );
                hasError = true;
            }
        }
    }

    if ( !hasError )
    {
        return;
    }

    // @ch 預設只 log（上方迴圈已 error()）；接了 handler 才上報/踢玩家，避免 SlotReels 直接耦合 framework
    this.m_onPlateDesync?.( errorObj );
}

/**
 * @ch 播放轉輪音效
 */
PlayReelSound()
{
    // soundAudioManager?.Play( Game_Define.AudioClips.reel_stop );
}

/**
 * @ch 更新停輪相關時間
 * @en Update stopTime, reelStopTime, reelPreTime and ClickStopBtn
 */
ClickStopBtn()
{
    if ( this.StopTime === 0 )
    {
        return;
    }

    this.m_isClickStopBtn = true;

    for ( let i = 0; i < Game_Define.COL; ++i )
    {
        let spinTime = this.m_cachedSpinTimes[ i ];
        let timesOfSpin = Math.ceil( this.m_time / spinTime ); // NOTE: 不加一的話有可能會偷換圖
        timesOfSpin = timesOfSpin > 0 ? timesOfSpin : 1;
        let reelPreTime = ( timesOfSpin - 1 ) * spinTime; // 差一圈就要停時的時間
        let reelStopTime = this.ToolsStrip( reelPreTime + spinTime );
        if ( this.m_reelStopTime[ i ] > reelStopTime )
        {
            this.m_reelStopTime[ i ] = reelStopTime;
            this.m_reelPreTime[ i ] = reelPreTime;
        }
    }

    // let stopTime = reelStopTime
    //     + this.m_spinDelayTime
    //     + this.m_spinBufferTime01
    //     + this.m_spinBufferTime02;

    // 轉輪節奏模組：三幣瑞龍
    // let stopTime = tempoSetting.TempoSetting.TripleCoinTreasure.SPEED_UP_STOP_TIME( 0, this.m_time );
    let stopTime = this.CalClickStopButtonFinishTime( this.m_time );

    if ( stopTime < this.m_stopTime )
    {
        this.StopTime = this.ToolsStrip( stopTime );
    }
}

/**
 * @ch 旋轉
 * @param dt 時間
 */
Spin( dt )
{
    this.m_time = this.ToolsStrip( this.m_time + dt );
    if ( this.IsStop )
    {
        return;
    }

    this.SpinAll( dt, NORMAL_COLUMNS );

    if ( this.StopTime === 0 || this.m_time <= this.StopTime )
    {
        return;
    }

    this.CheckPlateInfo();

    // 該停輪了
    this.m_isStop = true;

    if ( this.m_reelSoundId )
    {
        // soundAudioManager.Stop( this.m_reelSoundId );
        this.m_reelSoundId = null;
    }
}

