/**
 * @ch 測試 Standard Spin：啟動轉輪並設定假結果
 * @param plateSymbols 自訂盤面（可選），格式為 number[col][row]
 */
public TestStandardSpin(plateSymbols?: number[][]): void {
    if (!this.m_slotReel) {
        log("[ReelDevTool] 錯誤：未設定 SlotReel 引用");
        return;
    }

    const plate = plateSymbols || ReelDevTool.TEST_PLATE_STANDARD;
    log(`[ReelDevTool] === Standard Spin 測試開始 ===`);
    log(`[ReelDevTool] 盤面資料:`, JSON.stringify(plate));

    // 啟動轉輪
    this.m_slotReel.StartSpin();

    // 延遲設定結果（模擬伺服器回應延遲）
    this.scheduleOnce(() => {
        const cColumns = this.ConvertToCColumns(plate);
        this.m_slotReel.SetPlateInfo(cColumns);
        log(`[ReelDevTool] 已設定盤面結果，等待停輪...`);
    }, 0.5);
}

/**
 * @ch 測試全 WILD 盤面
 */
public TestAllWild(): void {
    this.TestStandardSpin(ReelDevTool.TEST_PLATE_ALL_WILD);
}

/**
 * @ch 測試 Scatter 觸發
 */
public TestScatterTrigger(): void {
    this.TestStandardSpin(ReelDevTool.TEST_PLATE_SCATTER);
}

