// uk_917 3 Leprechaun's Pots — proto STUB（自產仿真，非正式）
// ⏳ 正式 proto 未發佈。本檔依 docs/dev-spec.md §4 假設欄位撰寫，
//    骨架沿 1 代 lgs-protocol（SpinAck.RoundQueue）+ 模板消費形狀（eyestrike）。
//    正式 proto 發佈後：diff 本檔 vs 正式 .proto → 逐項核對 dev-spec §4 → 換掉 assets/Script/Proto.ts 的 import。
// 重新產生：proto-stub/ 下執行 npm run build（pbjs static-module commonjs + pbts，與正式套件同工藝）

syntax = "proto3";

package uk917Proto;

// ═══════════ 基礎結構（模板消費形狀，勿改名） ═══════════

message Column {
    repeated int32 Col = 1;
}

message IntAry {
    repeated int32 Data = 1;
}

// 盤面單格：Symbol=符號ID(0~27)、JPState=JP階級、Number=CASH面值
message CSymbol {
    int32 Symbol = 1;
    int32 JPState = 2;
    double Number = 3;
}

message CColumn {
    repeated CSymbol Col = 1;
}

message AwardData {
    int32 AwardType = 1;
    int32 Symbol = 2;
    int32 Count = 3;
    int32 Line = 4;
    double Win = 5;
    int32 Multiplier = 6;
}

// ═══════════ uk_917 特色結構（⏳ 全部為假設，dev-spec §4） ═══════════

message Position {
    int32 Col = 1;
    int32 Row = 2;
}

// F01 三盆：本手飛入明細（Color: 0=紫Expand 1=紅Multiplier 2=綠Bomb 3=Super）
message ScatterGain {
    int32 Color = 1;
    Position Pos = 2;
}

// F04 乘倍格（server 每手完整下發全盤，client 不本地累加）
message MultiplierCell {
    Position Pos = 1;
    int32 Multiplier = 2;
    bool IsNew = 3;
}

// F05 炸彈作用一格的變化（Action: 0=new_cash 1=upgrade_cash）
message AffectedCell {
    Position Pos = 1;
    int32 Action = 2;
    double CashValue = 3;
    double PreviousValue = 4;
}

// F05 單顆炸彈作用結果（按作用順序排列，client 逐顆依序播）
message BombResult {
    Position BombPos = 1;
    repeated AffectedCell AffectedCells = 2;
}

// F06 妖精投擲（Timing: 0=spinning 1=afterStop；afterStop 與神秘事件互斥）
message BombEvent {
    int32 Timing = 1;
    repeated Position Bombs = 2;
}

// F07 神秘事件：第5輪逐格重轉（Skip=該格已有COLLECT不轉）
message CollectMysteryCell {
    Position Pos = 1;
    bool Skip = 2;
    int32 ResultSymbol = 3;
}

// F07（Direction: 0=down 1=up）
message CollectMystery {
    int32 Direction = 1;
    repeated CollectMysteryCell Cells = 2;
}

// F08 聽牌（Kind: 0=none 1=collect 2=cash）
message NearMiss {
    int32 Kind = 1;
    int32 TriggerColumn = 2;
}

// F12 CASH 升階（Type: 0=銅 1=銀 2=金；⏳ 待核對：也可能改由 client 讀門檻表判定）
message CashUpgrade {
    Position Pos = 1;
    int32 FromType = 2;
    int32 ToType = 3;
}

// ═══════════ 模板相容殘留（eyestrike demo 讀取用，M1 清完 GameView/RecoverSpinAck 後可刪） ═══════════

message MultiplierUpgradeInfo {
    bool Upgrade = 1;
    int32 MultiplierIndex = 2;
    int32 Multiplier = 3;
}

message EnergyLevelUpgradeInfo {
    bool Upgrade = 1;
    int32 EnergyLevel = 2;
}

// ═══════════ 回合 / 回應 ═══════════

message RoundInfo {
    // —— 模板既有消費欄位 ——
    repeated CColumn MainPlateSymbol = 1;
    repeated CColumn FreePlateSymbol = 2;
    repeated CColumn FreePlateSymbolLog = 3;
    repeated AwardData AwardDataVec = 4;
    int32 AwardTypeFlag = 5;
    double RoundWin = 6;
    int32 MGReelWeightResult = 7;
    bool MaxFlag = 8;
    repeated IntAry FeaturePosQueue = 9;
    int32 FreeRemainRound = 10;
    int32 FreeNowRound = 11;
    int32 FreeTotalRound = 12;

    // —— 1 代 lgs 衍生（Collect Feature） ——
    double LineWin = 13;
    double CollectWin = 14;
    repeated int32 Collected = 15;

    // —— uk_917 特色（⏳ 全部假設） ——
    repeated int32 PotStages = 16;              // 3 盆當前階段 [紫,紅,綠]（0~2）
    repeated ScatterGain ScatterGains = 17;     // F01 本手飛入
    int32 TriggerFeatures = 18;                 // FG 觸發組合 bitmask：1=Expand 2=Multiplier 4=Bomb（1~7）
    int32 NewFeature = 19;                      // FG retrigger 新特色（0=無）
    int32 AddRound = 20;                        // retrigger 追加局數
    repeated MultiplierCell MultiplierGrid = 21; // F04 全盤乘倍現況
    repeated BombResult BombResults = 22;       // F05
    BombEvent BombEvent = 23;                   // F06
    CollectMystery CollectMystery = 24;         // F07
    NearMiss NearMiss = 25;                     // F08
    bool BigWinAnnounce = 26;                   // F09 大獎預告
    repeated CashUpgrade CashUpgrades = 27;     // F12
    int32 AddSpinCount = 28;                    // F10 +1 SPIN 數

    // —— eyestrike 殘留（模板 code 讀取，M1 清理後可刪） ——
    int32 CurrFeverGameType = 40;
    int32 NextFeverGameType = 41;
    int32 FreeGameWheelIndex = 42;
    int32 FreeGameWheelNumberIndex = 43;
    int32 PreMultiplierIndex = 44;
    int32 MainMultiplierIndex = 45;
    int32 FreeMultiplierIndex = 46;
    repeated MultiplierUpgradeInfo MultiplierUpgrade = 47;
    int32 PreEnergyLevel = 48;
    int32 EnergyLevel = 49;
    int32 EnergyPoint = 50;
    repeated EnergyLevelUpgradeInfo EnergyLevelUpgrade = 51;
}

message SpinAck {
    repeated RoundInfo RoundQueue = 1;
    double FreeTotalWin = 2;
    double TotalWin = 3;
    double Bet = 4;
    // 1 代 lgs 衍生
    double RTP = 5;
    int32 RID = 6;
    int32 LID = 7;
    // eyestrike 殘留
    int32 MultiplierIndex = 40;
    int32 EnergyLevel = 41;
    int32 EnergyPoint = 42;
}

message GameInfoData {
    bool ShowExtra = 1;
    repeated double Mul = 2;
    repeated double JPOdds = 3;
    repeated int32 PotStages = 4;               // ⏳ 斷線恢復：3 盆階段
    // eyestrike 殘留
    repeated IntAry WheelData = 40;
    int32 MultiplierIndex = 41;
    int32 EnergyLevel = 42;
    int32 EnergyPoint = 43;
}

