    /**
     * @ch 隱藏靜態全盤面
     * @param delayTime 延遲時間
     */
    async HidePlate( delayTime = 0 )
    {
        await Define.Wait( this, delayTime );
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            this.AllColumns[ this.MiddlePlateIndex ][ col ].SetColumnVisiable( false );
        }
    }

    /** @ch 顯示靜態全盤面 */
    ShowPlate()
    {
        // this.m_gameView.EffectPlate.ReturnAll();
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            this.AllColumns[ this.MiddlePlateIndex ][ col ].SetColumnVisiable( true );
        }
    }

    // =============== 彈性轉輪系統：符號替換機制 ===============    
    /**@ch AddReelTimes：增加轉輪圈數
     * @param columnIndex 列索引 (0 ~ Game_Define.COL-1)
     * @param additionalTimes 增加的圈數
     */
    AddReelTimes( columnIndex: number, additionalTimes: number )
    {
        if ( columnIndex < 0 || columnIndex >= Game_Define.COL )
        {
            console.error( `AddReelTimes: 無效的列索引 ${columnIndex}` );
            return;
        }

        // 更新停輪時間
        if ( this.m_reelStopTime && this.m_reelPreTime )
        {
            const additionalTime = additionalTimes * this.m_spinTime;
            this.m_reelStopTime[ columnIndex ] += additionalTime;
            this.m_reelPreTime[ columnIndex ] += additionalTime;
        }        
    }

    /**@ch 設定Column鎖定 */
    SetColumnLock( col: number, isLock: boolean )
    {   
        if ( col < 0 || col >= Game_Define.COL )
        {
            console.error( `SetColumnLock: 無效的列索引 ${col}` );
            return;
        }

        this.m_lockColumn[ col ] = isLock;
    }


    // =============== 彈性轉輪系統：公開介面 ===============

    /**
     * @ch 設定盤面結構配置
     * @param config 盤面結構配置（plateCount、每列 target/visible、假符號策略等）
     * @description
     *   建議在 GameView init 早期、CreateSymbol 之前呼叫一次。
     *   若在 CreateSymbol 之後改 config（例如切換 free game 用不同盤面），
     *   會自動重算 ColumnSymbol 大小、總長度與 Y 座標。
     *   注意：執行期切換不會改動 plateCount（上下假盤面已建/未建無法事後動態改）。
     */
    public SetLayoutConfig( config: ReelLayoutConfig )
    {
        this.m_layoutConfig = config;

        // 已建立盤面後才呼叫 → 重新調整現有 ColumnSymbol
        if ( this.m_plateInfo.length > 0 )
        {
            this.AdjustColumnSymbolCounts();
        }
        else
        {
            // 即使尚未建立盤面，也要更新位置 / 長度相關陣列
            this.UpdateTotalLengths();
            this.UpdateReelYPositions();
            this.UpdateComparePosArray();
        }
    }

    /**@ch 切換轉輪方向
     * @param direction 轉輪方向
     */
    public SwitchReelDirection( direction: ReelDirection )
    {
        this.m_reelDirection = direction;
        this.UpdateComparePosArray();
    }

    // =============== 補位策略系統 ===============

    /**@ch 當前玩法模式 */
    private m_spinMode: SpinMode = SpinMode.Standard;
    public get CurrentSpinMode(): SpinMode { return this.m_spinMode; }

    /**@ch 補位策略實例 */
    private m_fillStrategy: IFillStrategy = null;
    public get FillStrategy(): IFillStrategy { return this.m_fillStrategy; }

    /**
     * @ch 設定轉輪玩法模式和補位策略
     * @param mode 玩法模式
     * @param strategy 補位策略（Standard 模式可不傳）
     */
    public SetSpinMode(mode: SpinMode, strategy?: IFillStrategy): void {
        this.m_spinMode = mode;
        this.m_fillStrategy = strategy || null;

        if (this.m_fillStrategy && this.m_allColumns.length > 0) {
            this.m_fillStrategy.Init(
                this.m_allColumns[this.MiddlePlateIndex],
                (col: number, row: number) => {
                    const visibleCount = this.GetVisibleSymbolCount(col);
                    if (row >= visibleCount) return null;
                    return this.GetMiddleSymbolEmptyNodeFromColRow(col, row);
                },
                (position: number) => this.GetColRowFromPosition(position)
            );
        }
    }

    /**
     * @ch 執行消除（隱藏指定位置的符號）
     * @param data 消除資料
     * @returns Promise，消除完成後 resolve
     */
    public async Explode(data: ExplodeData): Promise<void> {
        if (!this.m_fillStrategy) {
            error("[SlotReel] Explode: 未設定 FillStrategy");
            return;
        }

        // 隱藏被消除的符號節點
        for (const pos of data.positions) {
            const { col, row } = this.GetColRowFromPosition(pos);
            const column = this.m_allColumns[this.MiddlePlateIndex][col];
            if (column) {
                column.HideSymbolByRow(row);
            }
        }

        // 委派給策略執行消除動畫
        await this.m_fillStrategy.Explode(data);
    }

    /**
     * @ch 執行補位（天降/雪崩）
     * @param data 補位資料
     * @returns Promise，補位完成後 resolve
     */
    public async Fill(data: FillData): Promise<void> {
        if (!this.m_fillStrategy) {
            error("[SlotReel] Fill: 未設定 FillStrategy");
            return;
        }

        await this.m_fillStrategy.Fill(data);
    }

    /**
     * @ch 重置補位策略狀態（新一輪開始時呼叫）
     */
    public ResetFillStrategy(): void {
        if (this.m_fillStrategy) {
            this.m_fillStrategy.Reset();
        }
    }

    /**
     * @ch 取得中間盤面的 ColumnSymbol 陣列（供策略使用）
     */
    public GetMiddleColumns(): ColumnSymbol[] {
        return this.m_allColumns[this.MiddlePlateIndex] || [];
    }

    // =============== 進場策略系統 ===============

    /**@ch 進場策略實例（null = 使用預設轉輪旋轉） */
    private m_entryStrategy: IEntryStrategy = null;
    public get EntryStrategy(): IEntryStrategy { return this.m_entryStrategy; }

    /**
     * @ch 設定進場策略
     * @param strategy 進場策略（null = 使用預設轉輪旋轉）
     * @description 設為非 null 時，會把上下假盤面隱藏（DropEntry 不需要無限轉輪帶視覺）。
     *              設回 null 時恢復顯示，讓 Standard 轉輪滾動可正常運作。
     */
    public SetEntryStrategy(strategy: IEntryStrategy | null): void {
        this.m_entryStrategy = strategy;
        if (this.m_entryStrategy && this.m_allColumns.length > 0) {
            this.m_entryStrategy.Init(
                this.m_allColumns[this.MiddlePlateIndex],
                (col: number, row: number) => {
                    // 安全取得固定位置節點，超出範圍時回傳 null
                    const visibleCount = this.GetVisibleSymbolCount(col);
                    if (row >= visibleCount) return null;
                    return this.GetMiddleSymbolEmptyNodeFromColRow(col, row);
                }
            );
            this.SetNonMiddlePlatesVisible(false);
        } else if (!this.m_entryStrategy && this.m_allColumns.length > 0) {
            this.SetNonMiddlePlatesVisible(true);
        }
    }

    /**
     * @ch 切換上下假盤面（plate ≠ MiddlePlateIndex）的顯示
     * @param visible true = 顯示（Standard 轉輪滾動需要），false = 隱藏（DropEntry 不需要）
     * @description 只動 SetColumnVisiable，不銷毀節點，切回 Standard 時可立即恢復。
     */
    private SetNonMiddlePlatesVisible(visible: boolean): void {
        for (let plate = 0; plate < this.m_allColumns.length; plate++) {
            if (plate === this.MiddlePlateIndex) continue;
            const columns = this.m_allColumns[plate];
            if (!columns) continue;
            for (const col of columns) {
                col?.SetColumnVisiable(visible);
            }
        }
    }

    /**
     * @ch 開始掉落式進場（EntryStrategy 模式下取代 StartSpin）
     */
    public StartDropEntry(): void {
        if (!this.m_entryStrategy) return;
        this.m_isStop = false;
        this.m_entryStrategy.StartEntry();
    }

    /**
     * @ch 設定掉落式進場的結果盤面（從 m_plateInfo 轉換）
     * @description 在 SetPlateInfo 之後呼叫，將已設定的盤面資料傳給 EntryStrategy
     */
    public SetDropResultFromPlateInfo(): void {
        if (!this.m_entryStrategy) return;
        if (!this.m_plateInfo || this.m_plateInfo.length === 0) return;

        const symbolInfos: SymbolInfo[][] = [];
        for (let col = 0; col < this.m_plateInfo.length; col++) {
            symbolInfos[col] = [];
            const colData = this.m_plateInfo[col]?.Col;
            if (!colData) continue;
            for (let row = 0; row < colData.length; row++) {
                const info = new SymbolInfo();
                info.Symbol = colData[row]?.Symbol ?? 0;
                info.Value = colData[row]?.Number ?? 0;
                info.JpType = colData[row]?.JPState ?? 0;
                symbolInfos[col].push(info);
            }
        }

        this.m_entryStrategy.SetResult(symbolInfos);
    }

    /**
     * @ch 更新掉落式進場（在 SpinState.OnProcess 中呼叫）
     * @param dt 時間差
     * @returns true = 進場完成
     */
    public UpdateDropEntry(dt: number): boolean {
        if (!this.m_entryStrategy) return true;
        const complete = this.m_entryStrategy.Update(dt);
        if (complete) {
            this.m_isStop = true;
            // DropEntry 落地完成 → 播 Scatter 動畫（下一輪 SpinState.OnEnter 清理）
            if (this.m_gameView?.EffectPlate) {
                for (let col = 0; col < Game_Define.COL; col++) {
                    const colData = this.m_plateInfo?.[col]?.Col;
                    if (!colData) continue;
                    for (let row = 0; row < colData.length; row++) {
                        if ((colData[row]?.Symbol ?? colData[row]) === Game_Define.SCATTER_SYMBOL) {
                            this.m_gameView.EffectPlate.PlayScatterAnimation(col, row, 'Stop', false);
                        }
                    }
                }
            }
        }
        return complete;
    }

    /**
     * @ch 強制停止掉落式進場
     */
    public ForceStopDropEntry(): void {
        if (!this.m_entryStrategy) return;
        this.m_entryStrategy.ForceStop();
        this.m_isStop = true;
    }
}

import { _decorator, Component, UITransform, Size, Vec3, v3, Node, error, Enum, log } from "cc";
import Game_Define, { SymbolInfo } from "./Game_Define";
import GameView from "./GameView";
