    //#region ConnectionManager
    // ConnectionManager需實作 OnCommand、GetSpinInfo、CancelSpin
    OnCommand( type: number, data: Uint8Array )
    {
        console.log( "OnCommand", type );
        switch ( type )
        {
            case Define.AckType.info:
                {
                    console.log( "OnCommand Define.AckType.info" );

                    let info: protocol.ar2esProto.IGameInfoData = protocol.ar2esProto.GameInfoData.decode( data );
                    // console.error( "GameInfo is", info );                    

                    eventManager.Dispatch(GAME_INTRO_MANAGER_EVENT.INIT, this);

                    this.SetTxt();

                    this.SettingBottomBar();

                    newBottombarManager.AutoPlayPanelInit();
                    newExtraManager.FeaturesInit(
                        [ "features/left/spriteFrame", "features/right/spriteFrame" ],
                        [ Game_Define.StringKey.MC_FEATURES_LEFT, Game_Define.StringKey.MC_FEATURES_RIGHT ],
                        Game_Define.SPICY_LEVEL,
                        this.m_titleSpriteAtlas
                    );
                    let atlas: SpriteAtlas = localeStringManager.GetGameAtlas();
                    newExtraManager.SetFeatruesDesc( [ atlas.getSpriteFrame( "txt1" ), atlas.getSpriteFrame( "txt2" ) ] );
                    newExtraManager.CheckFirstFeatures();

                    this.m_buyBonus?.Init( commonGameManager.GameMallInfo, this );

                    // newBottombarManager.SetWinValue( 0 );
                    newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );

                    newBottombarManager.SetTxt();
                    newExtraManager.SetTxt();
                    this.OnRotation();
                    newBottombarManager.SetAutoPlayPanelTxt();
                    newBottombarManager.SetAutoPlaySettingPanelFreeGameString( Define.StringKey.AUTO_PLAY_PANEL_ENTER_FREEGAME );

                    newExtraManager.SetCanAutoShowRankboardUI();

                    //音效
                    this.LoadSound();
                    break;
                }
            case Define.AckType.lastSpin:
            case Define.AckType.spin:
                {
                    console.log( "OnCommand Define.AckType.lastSpin" );

                    let info: protocol.ar2esProto.ISpinAck = protocol.ar2esProto.SpinAck.decode(data);
                    this.OnRecvSpinAck(info);
                    break;
                }

            case Define.AckType.unshow: {
                console.log( "OnCommand Define.AckType.unshow" );

                let info: protocol.ar2esProto.ISpinAck = protocol.ar2esProto.SpinAck.decode( data );
                this.m_unshowSpinAck = info;
                break;
            }
        }
    }

