    /**@ch 設定底條 */
    private SettingBottomBar() {
        newBottombarManager.VerString = "v_" + Define.VERSION + "_" + Game_Define.Ver;
        newBottombarManager.IsSendBetChange = true;
        newBottombarManager.IsSendBetViewOpen = true;
        newBottombarManager.SetTouchEvet((event: Event) => {
            this.BarTouchCb(event);
        });

        newBottombarManager.HaveStopSound(false);
        Game_Define.ShowDisplayValue = (value: number) => {
            return newBottombarManager.GetDisplayValue(value);
        };

        // 取得前導Play按鈕的圖片
        let titleSprite = this.m_logoSpriteFrame = this.m_titleSpriteAtlas?.getSpriteFrame("logo_" + localeStringManager.CurrLang);

        // 顯示前導Play按鈕
        newBottombarManager.ShowPlayReady(titleSprite,
            () => {
                if (stateManager.Current() === Game_Define.GameState.WAIT_READY) {
                    stateManager.NextState(Game_Define.GameState.PLATE_SHOW);
                    return false;
                }
                return true;
            },
            () => {
                if (stateManager.Current() === Game_Define.GameState.WAIT_READY) {
                    if (newExtraManager.IsFeaturesDemo) {

                        // 若要展示特色，設定需要展示特色
                        /*
                        if (this.m_featureShowState)
                        {
                            this.m_featureShowState.IsNeedFeatureDemo = true;
                        }
                        */
                        stateManager.NextState(Game_Define.GameState.FEATURE_SHOW);
                    }
                    else {
                        stateManager.NextState(Game_Define.GameState.PLATE_SHOW);
                    }
                }
            }
        );
        newBottombarManager.SetFollowNode(this.node);
        iframeCommandManager.AddCb({
            StopAutoCb: () => {
                newBottombarManager.ShowAutoPlayState(false);
            }
        });

        this.m_plateSpinBtn?.node.on(
            Node.EventType.TOUCH_END,
            (evt: EventTouch) => {
                newBottombarManager.SendSpinLog();
                this.BarTouchCb(evt);
            }
        );

        newBottombarManager.SetAutoplayConfirmCb((otherInfos: string) => {
            this.m_autoplayInfos = JSON.parse(otherInfos);
            if (stateManager.Current() === CommonState.IDLE) {
                eventManager.Dispatch(CommonEventName.SpinReqNotify);
                // soundAudioManager.Play(Game_Define.AudioClips.Spin);
            }
            this.m_buyBonus?.Hide();
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_AUTOPLAY);
        });
        tools.CloseIntroLoading.push(() => {
            if (commonGameManager.HasUnshow) {
                stateManager.NextState(Game_Define.GameState.UNSHOW_PREPARE);
            }
        });

        this.m_isBottombarFinished = true;
    }

    /**@ch 底條觸發事件 */
    private BarTouchCb(event: Event) {
        // log("bar event", event);
        let name = event?.target?.name;
        // log("bar event", name);

        switch (name) {
            case this.m_plateSpinBtn?.node.name:
                if (tools.CheckSwitchOff(SwitchOffKeyDefine.NoQuickSpin)) {
                    break;
                }

                if (stateManager.Current() === CommonState.IDLE) {
                    if (!this.m_isFirstPlateSpin) {
                        this.m_spinClickEvent = Define.BTN_CLICK_EVENT.CLICK_PLATE;
                        this.ClickSpin();
                    }
                    else {
                        this.m_isFirstPlateSpin = false;
                        let setting: MsgBoxSetting = {} as MsgBoxSetting;
                        setting.contextKey = Define.StringKey.MSGBOX_TOUCHPANEL_SPIN;
                        setting.titleKey = Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO;
                        setting.showCancelBtn = false;
                        setting.showConfirmBtn = true;
                        setting.showCloseBtn = true;
                        setting.confirmCB = () => {
                            this.m_spinClickEvent = Define.BTN_CLICK_EVENT.CLICK_PLATE;
                            this.ClickSpin();
                        };
                        msgBoxManager.PushMessageBoxSetting(setting);
                    }
                }
                else {
                    if (this.CanPlateStop) {
                        this.ClickStop();
                    }
                }
                break;
            case BottomBar_UIName.BTN_SPIN:
            case BottomBar_UIName.BTN_SPINSTOP:
                if (stateManager.Current() === CommonState.IDLE) {
                    this.m_spinClickEvent = Define.BTN_CLICK_EVENT.SPIN;
                    this.ClickSpin();
                }
                else if (this.CanPlateStop) {
                    this.ClickStop();
                }
                break;
            case BottomBar_UIName.BTN_AUTOPLAY:
                if (!tools.CheckSwitchOff(SwitchOffKeyDefine.ShowAutoSetting)) {
                    break;
                }
            // eslint-disable-next-line no-fallthrough
            case BottomBar_UIName.BTN_WISEAUTOPLAY:
                // 開啟智慧自動玩面板
                if (newBottombarManager.IsAutoSpin) {
                    newBottombarManager.ShowAutoPlayState(false);
                    newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_CANCEL);
                }
                newBottombarManager.ShowAutoplaySettingView(newBottombarManager.GetChips());
                break;
            case BetValueChange: {
                // TODO 若切換Bet時有需要額外處理，可在這裡處理或送事件
                eventManager.Dispatch( GAME_EVENT.CHANGE_BET, newBottombarManager.GetNowBetValue() );
                break;
            }
            case BottomBar_UIName.BTN_AUTOSTOP_C:
            case BottomBar_UIName.BTN_AUTOSTOP:
                // 按下取消自動按鍵
                newBottombarManager.ShowAutoPlayState(false);
                newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_CANCEL);
                /*
                if (this.BigWin &&!this.BigWin.IsEnd) {
                    newBottombarManager.SetSpinState(SlotBottomBarState.SKIP_SMALL_FLASH_AUTOPLAY);
                }
                */
                break;
            default: {
                let betIndex = Number(name);
                if (betIndex === -1) {
                    let bet = newBottombarManager.GetNowBetValue();
                    betIndex = newBottombarManager.FindBetIndexByValue(bet);
                }
                let betList = newBottombarManager.GetBetList();
                if (!isNaN(betIndex) && betIndex < betList.length) {
                    // 通知更換BET
                    eventManager.Dispatch( GAME_EVENT.CHANGE_BET, newBottombarManager.GetNowBetValue() );
                }
                break;
            }
        }
    }
