    /**@ch 取得symbol的idx */
    private GetIdx(name: string) {
        // reg 需依需求調整
        let reg = /Symbol_(\d{2})/g;
        let result: number[] = [];
        let res = reg.exec(name);

        // result 大小依遊戲需求改變(MEGA Way會有兩個參數)
        for (let i = 0; i < res.length; ++i) {
            let value = Number(res[i]);
            if (!isNaN(value)) {
                result.push(value);
            }
        }
        return result;
    }

    /**@ch 動態載入symbol */
    private LoadSymbol() {
        let path = this.m_loadPath.trim() + "Img/Symbol";
        Define.GameBundle.loadDir(
            path,
            SpriteFrame,
            (error: Error, assets: SpriteFrame[]) => {
                if (error) {
                    this.LoadSymbol();
                    return;
                }

                // 過濾掉檔名中沒有 Symbol_XX 格式的資源
                assets = assets.filter((asset: SpriteFrame) => {
                    let idx = this.GetIdx(asset.name);
                    return idx.length > 0;
                });

                assets.sort((a: SpriteFrame, b: SpriteFrame) => {
                    let AIdx: number[] = this.GetIdx(a.name);
                    let BIdx: number[] = this.GetIdx(b.name);

                    if (AIdx[0] < BIdx[0]) {
                        return -1;
                    }
                    else if (AIdx[0] > BIdx[0]) {
                        return 1;
                    }
                    else {
                        return 0;
                    }
                });

                this.m_symbolSpriteFrames = assets;

                // 空節點
                this.m_symbolSpriteFrames.push(null);

                // 設定盤面結構（在 CreateSymbol 前呼叫）
                //   Standard 轉輪：REEL_LAYOUT_PRESETS.standard（3 層）
                //   DropEntry 玩法：REEL_LAYOUT_PRESETS.dropEntry（1 層）
                this.m_slotReels?.SetLayoutConfig(REEL_LAYOUT_PRESETS.standard);
                this.SlotReels?.CreateSymbol();
            });
    }
