    public get ComboIdx(): number { return this.m_comboIdx; }

    /**@ch 消除資料陣列（由伺服器回傳，每個元素代表一次消除） */
    private m_explodeDataList: ExplodeData[] = [];

    /**@ch 補位資料陣列（由伺服器回傳，每個元素代表一次補位） */
    private m_fillDataList: FillData[] = [];

    /**
     * @ch 設定 Cascade/Tumble 的多階段資料
     * @param explodeList 消除資料陣列
     * @param fillList 補位資料陣列
     */
    public SetComboData(explodeList: ExplodeData[], fillList: FillData[]): void {
        this.m_comboIdx = 0;
        this.m_explodeDataList = explodeList;
        this.m_fillDataList = fillList;
    }

    /**
     * @ch 取得當前階段的消除資料
     * @returns 消除資料，若已無更多階段則回傳 null
     */
    public GetCurrentExplodeData(): ExplodeData | null {
        if (this.m_comboIdx >= this.m_explodeDataList.length) {
            return null;
        }
        return this.m_explodeDataList[this.m_comboIdx];
    }

    /**
     * @ch 取得當前階段的補位資料
     * @returns 補位資料，若已無更多階段則回傳 null
     */
    public GetCurrentFillData(): FillData | null {
        if (this.m_comboIdx >= this.m_fillDataList.length) {
            return null;
        }
        return this.m_fillDataList[this.m_comboIdx];
    }

    /**
     * @ch 推進 combo 索引到下一階段
     */
    public AdvanceComboIndex(): void {
        this.m_comboIdx++;
    }

    /**
     * @ch 重置 combo 資料（新一輪開始時呼叫）
     */
    public ResetComboData(): void {
        this.m_comboIdx = 0;
        this.m_explodeDataList = [];
        this.m_fillDataList = [];
    }

    /**
     * @ch 注入 Mock Cascade 資料（純 Log 驗證用）
