                { positions: [5, 8] },           // 第 2 次消除：col1 row0 + col1 row3
                { positions: [] },               // 第 3 次：無消除（結束循環）
            ],
            [
                { fillSymbols: [[3, 4, 5], [], [], [], []] },  // 第 1 次補位：col0 補 3 個
                { fillSymbols: [[], [7, 8], [], [], []] },     // 第 2 次補位：col1 補 2 個
            ]
        );
    }
}

import { _decorator, Component, log, Node } from "cc";
import { SlotReel } from "./SlotReels";
import Game_Define, { SymbolInfo } from "./Game_Define";
