    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseColumns( data: protocol.ar2esProto.IColumn[] ) : protocol.ar2esProto.Column[]
    {
        if ( !data || !Array.isArray(data) )
        {
            return [];
        }

        let ret: protocol.ar2esProto.Column[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            if ( !data[ i ] )
            {
                // 建立空的 Column 物件
                let emptyColumn = new protocol.ar2esProto.Column();
                emptyColumn.Col = [];
                ret.push( emptyColumn );
            }
            else
            {
                ret.push( this.TraverseColumn( data[ i ] ) );
            }
        }
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseColumn( data: protocol.ar2esProto.IColumn ) : protocol.ar2esProto.Column
    {
        let ret = new protocol.ar2esProto.Column();

        // 檢查輸入參數有效性
        if ( !data )
        {
            ret.Col = [];
            return ret;
        }

        // 確保 ret.Col 已初始化
        if ( !ret.Col )
        {
            ret.Col = [];
        }

        // 檢查 data.Col 是否存在且為陣列
        if ( !data.Col || !Array.isArray( data.Col ) )
        {
            ret.Col = [];
            return ret;
        }

        // 複製並處理每個元素，避免修改原始資料
        for ( let i = 0; i < data.Col.length; ++i )
        {
            let processedValue = this.EnsureNum( data.Col[ i ] );
