        // 檢查輸入參數有效性
        if ( !data )
        {
            ret.Col = [];
            return ret;
        }

        // 確保 ret.Col 已初始化
        if ( !ret.Col )
        {
            ret.Col = [];
        }

        // 檢查 data.Col 是否存在且為陣列
        if ( !data.Col || !Array.isArray( data.Col ) )
        {
            ret.Col = [];
            return ret;
        }

        // 複製並處理每個元素，避免修改原始資料
        for ( let i = 0; i < data.Col.length; ++i )
        {
            let processedValue = this.EnsureNum( data.Col[ i ] );
            ret.Col.push( processedValue );
        }

        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseCColumns( data: protocol.ar2esProto.ICColumn[] ) : protocol.ar2esProto.CColumn[]
    {
        if ( !data || !Array.isArray(data) )
        {
            return [];
        }

        let ret: protocol.ar2esProto.CColumn[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            if ( !data[ i ] )
            {
                let emptyColumn = new protocol.ar2esProto.CColumn();
                emptyColumn.Col = [];
                ret.push(emptyColumn);
            }
            else
            {
                ret.push(this.TraverseCColumn( data[ i ] ));
            }
        }
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseCColumn( data: protocol.ar2esProto.ICColumn ) : protocol.ar2esProto.CColumn
    {
        let ret = new protocol.ar2esProto.CColumn();
        if ( !data.Col )
        {
            return ret;
        }

        for ( let i = 0; i < data.Col.length; ++i )
        {
            ret.Col.push( this.TraverseCSymbol( data.Col[ i ] ) );
        }
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseCSymbol( data: protocol.ar2esProto.ICSymbol ) : protocol.ar2esProto.CSymbol
    {
        let ret = new protocol.ar2esProto.CSymbol();
        ret.Symbol = data.Symbol || 0;
        ret.JPState = data.JPState || 0;
        ret.Number = data.Number || 0;
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseAwardDataVec( data: protocol.ar2esProto.IAwardData[] ) : protocol.ar2esProto.AwardData[]
    {
        if ( !data || !Array.isArray(data) )
        {
            return [];
        }

        let ret: protocol.ar2esProto.AwardData[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            if ( data[ i ] )
            {
                let t = this.TraverseAwardData( data[ i ] );
                ret.push( t );
            }
        }
        return ret;
    }

    /**
     * @ch 處理整數陣列，確保每個數字都有效
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseIntegerList( data: number[] ) : number[]
    {
        if ( !data || !Array.isArray(data) )
        {
            return [];
        }

        let ret: number[] = [];
        for ( let i = 0; i < data.length; ++i )
        {
            let t = this.EnsureNum( data[ i ] );
            ret.push( t );
        }
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseAwardData( data: protocol.ar2esProto.IAwardData ) : protocol.ar2esProto.AwardData
    {
        let ret = new protocol.ar2esProto.AwardData();
        ret.AwardType = this.EnsureNum( data.AwardType );
        ret.Symbol = this.EnsureNum( data.Symbol );
        ret.Count = this.EnsureNum( data.Count );
        ret.Line = this.EnsureNum( data.Line );
        ret.Win = this.EnsureNum( data.Win );
        ret.Multiplier = this.EnsureNum( data.Multiplier );
        ret.JackpotWin = this.EnsureNum( data.JackpotWin );
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseArrays( data: boolean[] )
    {
        let ret = [];
        for ( let i = 0; i < data.length; ++i )
        {
            ret[ i ] = data[ i ];
        }
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    TraverseIntAry( data: protocol.ar2esProto.IIntAry ) : protocol.ar2esProto.IntAry
    {
        let ret = new protocol.ar2esProto.IntAry();
        ret.Data = data.Data || [];
        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param content 原始資料
     * @returns 轉換後的資料
     */
    ConvertPlate( content: Array<protocol.ar2esProto.ICColumn> ): Array<protocol.ar2esProto.CColumn>
    {
        if ( !content || !Array.isArray(content) )
        {
            return [];
        }

        let realPlate: protocol.ar2esProto.CColumn[] = [];
        for ( let i = 0; i < content.length; i++ )
        {
            if (content[i]) {
                let column = new protocol.ar2esProto.CColumn( content[ i ] );
                realPlate.push( column );
            } else {
                // 處理空項目，建立預設空列
                let emptyColumn = new protocol.ar2esProto.CColumn();
                emptyColumn.Col = [];
                realPlate.push( emptyColumn );
            }
        }
        return realPlate;
    }

    /**
     * @ch 確保數字不為空
     * @param input 原始資料
     * @returns 轉換後的資料
     */
    EnsureNum( input: number )
    {
        return input || 0;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 原始資料
     * @returns 轉換後的資料
     */
    ConvertCColumn( data: number[] ) : protocol.ar2esProto.CColumn
    {
        let ret = new protocol.ar2esProto.CColumn();

        // 檢查輸入有效性
        if (!data || !Array.isArray(data)) {
            ret.Col = [];
            return ret;
        }

        // 將每個符號 ID 轉換為完整的 CSymbol 物件
        ret.Col = data.map(symbol => {
            let cSymbol = new protocol.ar2esProto.CSymbol();
            cSymbol.Symbol = this.EnsureNum(symbol);
            cSymbol.JPState = 0;
            cSymbol.Number = 0;
            return cSymbol;
        });

        return ret;
    }

    /**
     * @ch 將Type從interface轉成class
     * @param data 
     * @returns 
     */
    ConvertCColumns( data: number[][] ) : protocol.ar2esProto.CColumn[]
    {
        if ( !data || !Array.isArray(data) )
        {
            return [];
        }

        let ret: protocol.ar2esProto.CColumn[] = [];
        for ( let i = 0; i < data.length; i++ )
        {
            ret.push( this.ConvertCColumn( data[ i ] ) );
        }
        return ret;
    }

    /**
     * 轉換成展示用的Ack
     * @param ack 
     * @param targetBet 
     * @returns 
     */
    ConvertDemoAck(ack : protocol.ar2esProto.ISpinAck, targetBet: number)
    {
        if (!ack)
            return;

        const winScale = targetBet / ack.Bet;
        if (winScale != 1)
        {
            ack.Bet = targetBet;
            ack.FreeTotalWin = tools.times(ack.FreeTotalWin, winScale);
            ack.TotalWin = tools.times(ack.TotalWin, winScale);
            ack.RoundQueue.forEach(roundInfo =>
                {
                    roundInfo.RoundWin = tools.times(roundInfo.RoundWin, winScale);
                    if (roundInfo.AwardDataVec)
                    roundInfo.AwardDataVec.forEach(adv => {adv.Win = tools.times(adv.Win, winScale);});
                });
        }
    }
}

